  1→/**
  2→ * Acceptance Test Kit — Shared Infrastructure
  3→ *
  4→ * Boots an in-process Brain server with isolated SurrealDB namespace.
  5→ * All acceptance test suites (core, orchestrator, intent, coding-session, etc.)
  6→ * build on this shared setup.
  7→ */
  8→import { afterAll, beforeAll } from "bun:test";
  9→import { randomBytes, createHash } from "node:crypto";
 10→import { readFileSync } from "node:fs";
 11→import { join } from "node:path";
 12→import { RecordId, Surreal } from "surrealdb";
 13→import * as jose from "jose";
 14→import { createOpenRouter } from "@openrouter/ai-sdk-provider";
 15→import { createBrainServer } from "../../app/src/server/runtime/start-server";
 16→import { createRuntimeDependencies } from "../../app/src/server/runtime/dependencies";
 17→import { createSseRegistry } from "../../app/src/server/streaming/sse-registry";
 18→import { createInflightTracker } from "../../app/src/server/runtime/types";
 19→import { createNonceCache } from "../../app/src/server/oauth/nonce-cache";
 20→import { createLiveSelectManager } from "../../app/src/server/reactive/live-select-manager";
 21→import { createFeedSseBridge } from "../../app/src/server/reactive/feed-sse-bridge";
 22→// Agent activator + loop dampener are created inside createBrainServer
 23→import type { ServerConfig } from "../../app/src/server/runtime/config";
 24→import type { ServerDependencies, InflightTracker } from "../../app/src/server/runtime/types";
 25→import { createMcpClientFactory } from "../../app/src/server/tool-registry/mcp-client";
 26→
 27→// ── Shared AI dependencies for standalone acceptance tests ──
 28→
 29→const openrouter = createOpenRouter({ apiKey: requireTestEnv("OPENROUTER_API_KEY") });
 30→
 31→export const testAI = {
 32→  openrouter,
 33→  extractionModelId: requireTestEnv("EXTRACTION_MODEL"),
 34→  extractionModel: openrouter(requireTestEnv("EXTRACTION_MODEL")),
 35→  embeddingModel: openrouter.textEmbeddingModel(requireTestEnv("EMBEDDING_MODEL")),
 36→  embeddingDimension: Number(requireTestEnv("EMBEDDING_DIMENSION")),
 37→};
 38→
 39→/** @deprecated Use `testAI` instead. */
 40→export const smokeAI = testAI;
 41→
 42→export type AcceptanceTestRuntime = {
 43→  baseUrl: string;
 44→  surreal: Surreal;
 45→  namespace: string;
 46→  database: string;
 47→  port: number;
 48→};
 49→
 50→/** @deprecated Use `AcceptanceTestRuntime` instead. */
 51→export type SmokeTestRuntime = AcceptanceTestRuntime;
 52→
 53→export type AcceptanceSuiteOptions = {
 54→  /** Direct config overrides — applied to the ServerConfig object without touching process.env. */
 55→  configOverrides?: Partial<ServerConfig>;
 56→  /** Override mcpClientFactory for tests needing mock MCP servers. */
 57→  mcpClientFactoryOverride?: ServerDependencies["mcpClientFactory"];
 58→};
 59→
 60→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 61→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 62→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 63→
 64→/**
 65→ * Split SQL into statements respecting `{...}` block nesting.
 66→ * DEFINE FUNCTION / DEFINE EVENT bodies contain semicolons that are NOT
 67→ * statement terminators. Naively splitting on `;` breaks those bodies into
 68→ * orphaned fragments that corrupt the batch query.
 69→ */
 70→function splitSqlStatements(sql: string): string[] {
 71→  const stmts: string[] = [];
 72→  let current = "";
 73→  let depth = 0;
 74→  for (let i = 0; i < sql.length; i++) {
 75→    const ch = sql[i];
 76→    if (ch === "{") depth++;
 77→    else if (ch === "}") depth--;
 78→
 79→    if (ch === ";" && depth === 0) {
 80→      const trimmed = current.trim();
 81→      if (trimmed.length > 0) stmts.push(trimmed);
 82→      current = "";
 83→    } else {
 84→      current += ch;
 85→    }
 86→  }
 87→  const trimmed = current.trim();
 88→  if (trimmed.length > 0) stmts.push(trimmed);
 89→  return stmts;
 90→}
 91→
 92→/**
 93→ * Apply the base schema to a SurrealDB instance.
 94→ *
 95→ * DEFINE ANALYZER cannot run inside a transaction in SurrealDB v3.0+.
 96→ * The SDK may treat a multi-statement .query() as an implicit transaction,
 97→ * causing the analyzer and dependent FULLTEXT indexes to fail silently.
 98→ *
 99→ * We split the schema into three phases:
100→ * 1. DEFINE ANALYZER (must run outside any transaction)
101→ * 2. Schema definitions (DEFINE TABLE/FIELD/INDEX) — batch is fine
102→ * 3. Seed data (CREATE statements) — separate batch to isolate from index errors
103→ */
104→export async function applyTestSchema(surreal: Surreal): Promise<void> {
105→  const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
106→
107→  // Strip full-line comments before splitting — comments may contain semicolons
108→  // (e.g. "-- The edge is the source of truth; status is a derived consequence.")
109→  // which would create spurious fragments after the split.
110→  const withoutComments = schemaSql
111→    .split("\n")
112→    .filter((line) => !line.trimStart().startsWith("--"))
113→    .join("\n");
114→
115→  // Brace-aware split: only split on `;` outside `{...}` blocks.
116→  // DEFINE FUNCTION and DEFINE EVENT bodies contain semicolons that must not
117→  // be treated as statement terminators.
118→  const statements = splitSqlStatements(withoutComments);
119→
120→  // Phase 1: DEFINE ANALYZER (must be isolated)
121→  const analyzerStmts = statements.filter((s) => s.startsWith("DEFINE ANALYZER"));
122→  for (const stmt of analyzerStmts) {
123→    await surreal.query(stmt + ";");
124→  }
125→
126→  // Phase 2: Schema definitions (DEFINE TABLE/FIELD/INDEX/FUNCTION/EVENT)
127→  const schemaStmts = statements.filter(
128→    (s) => !s.startsWith("DEFINE ANALYZER") && !s.startsWith("CREATE"),
129→  );
130→  if (schemaStmts.length > 0) {
131→    await surreal.query(schemaStmts.map((s) => s + ";").join("\n"));
132→  }
133→
134→  // Phase 3: Seed data (CREATE statements) — isolated so index issues don't block seeds
135→  const seedStmts = statements.filter((s) => s.startsWith("CREATE"));
136→  if (seedStmts.length > 0) {
137→    await surreal.query(seedStmts.map((s) => s + ";").join("\n"));
138→  }
139→}
140→
141→export function setupAcceptanceSuite(
142→  suiteName: string,
143→  options?: AcceptanceSuiteOptions,
144→): () => AcceptanceTestRuntime {
145→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
146→  const namespace = `accept_${runId}`;
147→  const suiteSlug = suiteName
148→    .toLowerCase()
149→    .replace(/[^a-z0-9]+/g, "_")
150→    .replace(/^_+|_+$/g, "");
151→  const database = `${suiteSlug || "suite"}_${Math.floor(Math.random() * 100000)}`;
152→
153→  let runtime: AcceptanceTestRuntime | undefined;
154→  let server: ReturnType<typeof Bun.serve> | undefined;
155→  let runtimeSurreal: Surreal | undefined;
156→  let analyticsSurreal: Surreal | undefined;
157→  let inflight: InflightTracker | undefined;
158→  let setupSucceeded = false;
159→
160→  beforeAll(async () => {
161→    const surreal = new Surreal();
162→    await withTimeout(() => surreal.connect(surrealUrl), 10_000, "connect to SurrealDB");
163→    await withTimeout(
164→      () => surreal.signin({ username: surrealUsername, password: surrealPassword }),
165→      10_000,
166→      "authenticate with SurrealDB",
167→    );
168→
169→    await withTimeout(() => surreal.query(`DEFINE NAMESPACE ${namespace};`), 10_000, "define test namespace");
170→    await withTimeout(() => surreal.use({ namespace }), 10_000, "switch to test namespace");
171→    await withTimeout(() => surreal.query(`DEFINE DATABASE ${database};`), 10_000, "define test database");
172→    await withTimeout(
173→      () => surreal.use({ namespace, database }),
174→      10_000,
175→      "switch to test namespace/database",
176→    );
177→
178→    await withTimeout(() => applyTestSchema(surreal), 20_000, "apply schema");
179→
180→    // Reserve a port so betterAuth gets the real URL at init time
181→    const tempServer = Bun.serve({ port: 0, fetch: () => new Response() });
182→    const reservedPort = tempServer.port;
183→    tempServer.stop(true);
184→    const baseUrl = `http://127.0.0.1:${reservedPort}`;
185→
186→    const config: ServerConfig = {
187→      openRouterApiKey: requireTestEnv("OPENROUTER_API_KEY"),
188→      chatAgentModelId: requireTestEnv("CHAT_AGENT_MODEL"),
189→      extractionModelId: requireTestEnv("EXTRACTION_MODEL"),
190→      pmAgentModelId: process.env.PM_AGENT_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
191→      analyticsAgentModelId: requireTestEnv("ANALYTICS_MODEL"),
192→      embeddingModelId: requireTestEnv("EMBEDDING_MODEL"),
193→      embeddingDimension: Number(requireTestEnv("EMBEDDING_DIMENSION")),
194→      extractionStoreThreshold: Number(requireTestEnv("EXTRACTION_STORE_THRESHOLD")),
195→      extractionDisplayThreshold: Number(requireTestEnv("EXTRACTION_DISPLAY_THRESHOLD")),
196→      surrealUrl,
197→      surrealUsername,
198→      surrealPassword,
199→      surrealNamespace: namespace,
200→      surrealDatabase: database,
201→      port: reservedPort,
202→      betterAuthSecret: process.env.BETTER_AUTH_SECRET ?? "smoke-test-secret-at-least-32-chars-long",
203→      betterAuthUrl: baseUrl,
204→      githubClientId: process.env.GITHUB_CLIENT_ID ?? "smoke-test-github-id",
205→      githubClientSecret: process.env.GITHUB_CLIENT_SECRET ?? "smoke-test-github-secret",
206→      observerModelId: process.env.OBSERVER_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
207→      scorerModelId: process.env.SCORER_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
208→      anthropicApiUrl: process.env.ANTHROPIC_API_URL?.trim() || "https://api.anthropic.com",
209→      ...(process.env.ANTHROPIC_API_KEY?.trim() ? { anthropicApiKey: process.env.ANTHROPIC_API_KEY.trim() } : {}),
210→      inferenceProvider: "openrouter",
211→      selfHosted: false,
212→      worktreeManagerEnabled: false,
213→      baseUrl: baseUrl,
214→      orchestratorMockAgent: false,
215→      ...options?.configOverrides,
216→    };
217→
218→    const deps = await createRuntimeDependencies(config);
219→    runtimeSurreal = deps.surreal;
220→    analyticsSurreal = deps.analyticsSurreal;
221→    inflight = createInflightTracker();
222→
223→    const serverDeps: ServerDependencies = {
224→      config,
225→      surreal: deps.surreal,
226→      analyticsSurreal: deps.analyticsSurreal,
227→      auth: deps.auth,
228→      chatAgentModel: deps.chatAgentModel,
229→      extractionModel: deps.extractionModel,
230→      pmAgentModel: deps.pmAgentModel,
231→      analyticsAgentModel: deps.analyticsAgentModel,
232→      embeddingModel: deps.embeddingModel,
233→      observerModel: deps.observerModel,
234→      scorerModel: deps.scorerModel,
235→      sse: createSseRegistry(),
236→      inflight,
237→      asSigningKey: deps.asSigningKey,
238→      nonceCache: createNonceCache(),
239→      mcpClientFactory: options?.mcpClientFactoryOverride ?? createMcpClientFactory(),
240→      sandboxAgentAdapter: deps.sandboxAgentAdapter,
241→    };
242→    destroySandbox = deps.destroySandbox;
243→
244→    server = createBrainServer(serverDeps);
245→    const port = server.port;
246→
247→    // Start reactive coordination layer: LIVE SELECT -> Feed SSE Bridge -> SSE Registry
248→    const liveSelectManager = createLiveSelectManager({ surreal: deps.surreal });
249→    const feedSseBridge = createFeedSseBridge({
250→      liveSelectManager,
251→      sseRegistry: serverDeps.sse,
252→    });
253→    feedSseBridge.subscribeAll();
254→
255→    // Agent Coordinator is created inside createBrainServer (called above).
256→    // In prod, DEFINE EVENT webhooks call the coordinator endpoint.
257→    // In acceptance tests, observations trigger the coordinator via the same HTTP endpoint.
258→
259→    inflight.track(
260→      liveSelectManager.start().catch(() => undefined),
261→    );
262→
263→    runtime = { baseUrl, surreal, namespace, database, port };
264→    setupSucceeded = true;
265→  }, 60_000);
266→
267→  let destroySandbox: (() => Promise<void>) | undefined;
268→
269→  afterAll(async () => {
270→    // Drain fire-and-forget work (e.g. webhook extraction) before closing DB
271→    if (inflight) {
272→      await inflight.drain(15_000);
273→    }
274→
275→    if (server) {
276→      server.stop(true);
277→    }
278→
279→    // Destroy SandboxAgent embedded server if started
280→    if (destroySandbox) {
281→      await destroySandbox().catch(() => undefined);
282→    }
283→
284→    if (runtimeSurreal) {
285→      await runtimeSurreal.close().catch(() => undefined);
286→    }
287→    if (analyticsSurreal) {
288→      await analyticsSurreal.close().catch(() => undefined);
289→    }
290→
291→    if (!runtime) {
292→      return;
293→    }
294→
295→    if (setupSucceeded && !process.env.SMOKE_KEEP_DB) {
296→      try {
297→        await withTimeout(() => runtime!.surreal.query(`REMOVE DATABASE ${database};`), 10_000, "remove test database");
298→      } catch {
299→        // Best effort cleanup.
300→      }
301→
302→      try {
303→        await withTimeout(() => runtime!.surreal.query(`REMOVE NAMESPACE ${namespace};`), 10_000, "remove test namespace");
304→      } catch {
305→        // Best effort cleanup.
306→      }
307→    }
308→
309→    await withTimeout(() => runtime!.surreal.close(), 2_000, "close SurrealDB").catch(() => undefined);
310→  }, 20_000);
311→
312→  return () => {
313→    if (!runtime) {
314→      throw new Error("Acceptance runtime requested before suite setup completed");
315→    }
316→    return runtime;
317→  };
318→}
