361→// ---------------------------------------------------------------------------
362→// SSE Helpers
363→// ---------------------------------------------------------------------------
364→
365→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
366→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
367→  if (!response.ok || !response.body) {
368→    throw new Error(`Failed to open SSE stream (${response.status})`);
369→  }
370→
371→  const reader = response.body.getReader();
372→  const decoder = new TextDecoder();
373→  const events: T[] = [];
374→  let buffer = "";
375→
376→  const timeout = setTimeout(() => {
377→    void reader.cancel();
378→  }, timeoutMs);
379→
380→  try {
381→    while (true) {
382→      const { value, done } = await reader.read();
383→      if (done) {
384→        break;
385→      }
386→
387→      buffer += decoder.decode(value, { stream: true });
388→      const segments = buffer.split("\n\n");
389→      buffer = segments.pop() ?? "";
390→
391→      for (const segment of segments) {
392→        const dataLine = segment.split("\n").find((line) => line.startsWith("data: "));
393→        if (!dataLine) {
394→          continue;
395→        }
396→
397→        const event = JSON.parse(dataLine.slice("data: ".length)) as T;
398→        events.push(event);
399→
400→        if (event.type === "error") {
401→          const errorText = (event as { error?: string }).error;
402→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
403→        }
404→
405→        if (event.type === "done") {
406→          return events;
407→        }
408→      }
409→    }
410→  } finally {
411→    clearTimeout(timeout);
412→    reader.releaseLock();
413→  }
414→
415→  return events;
416→}
