450→/**
451→ * Obtain an OAuth2 JWT access token for MCP endpoints.
452→ * Requires a SurrealDB connection to skip consent screen.
453→ */
454→export async function getOAuthToken(
455→  baseUrl: string,
456→  surreal: Surreal,
457→  sessionHeaders: Record<string, string>,
458→  scopes: string = "graph:read graph:reason session:write offline_access",
459→): Promise<string> {
460→  // Trigger JWKS key generation if not yet done
461→  await fetch(`${baseUrl}/api/auth/jwks`);
462→
463→  const dcrRes = await fetch(`${baseUrl}/api/auth/oauth2/register`, {
464→    method: "POST",
465→    headers: { "Content-Type": "application/json" },
466→    body: JSON.stringify({
467→      client_name: `test-client-${Date.now()}`,
468→      redirect_uris: ["http://127.0.0.1:9999/callback"],
469→      grant_types: ["authorization_code", "refresh_token"],
470→      response_types: ["code"],
471→      token_endpoint_auth_method: "none",
472→    }),
473→  });
474→  if (!dcrRes.ok) throw new Error(`DCR failed: ${dcrRes.status} ${await dcrRes.text()}`);
475→
476→  const { client_id } = (await dcrRes.json()) as { client_id: string };
477→
478→  await surreal.query(`UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`, {
479→    cid: client_id,
480→  });
481→
482→  const { verifier, challenge } = generatePkce();
483→  const authUrl = new URL(`${baseUrl}/api/auth/oauth2/authorize`);
484→  authUrl.searchParams.set("client_id", client_id);
485→  authUrl.searchParams.set("redirect_uri", "http://127.0.0.1:9999/callback");
486→  authUrl.searchParams.set("response_type", "code");
487→  authUrl.searchParams.set("scope", scopes);
488→  authUrl.searchParams.set("state", "test-state");
489→  authUrl.searchParams.set("code_challenge", challenge);
490→  authUrl.searchParams.set("code_challenge_method", "S256");
491→  authUrl.searchParams.set("resource", baseUrl);
492→
493→  const authRes = await fetch(authUrl.toString(), {
494→    headers: sessionHeaders,
495→    redirect: "manual",
496→  });
497→  if (authRes.status !== 302) throw new Error(`Authorize did not redirect: ${authRes.status}`);
498→
499→  const location = authRes.headers.get("location")!;
500→  const redirectUrl = new URL(location, baseUrl);
501→  const code = redirectUrl.searchParams.get("code") ?? "";
502→  if (!code) throw new Error(`No code in redirect: ${location}`);
503→
504→  const tokenRes = await fetch(`${baseUrl}/api/auth/oauth2/token`, {
505→    method: "POST",
506→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
507→    body: new URLSearchParams({
508→      grant_type: "authorization_code",
509→      code,
510→      redirect_uri: "http://127.0.0.1:9999/callback",
511→      client_id,
512→      code_verifier: verifier,
513→      resource: baseUrl,
514→    }),
515→  });
516→  if (!tokenRes.ok) throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
517→
518→  const tokens = (await tokenRes.json()) as { access_token: string };
519→  return tokens.access_token;
520→}
521→
522→export type DPoPKeyPair = {
523→  privateKey: CryptoKey;
524→  publicKey: CryptoKey;
525→  publicJwk: JsonWebKey;
526→  thumbprint: string;
527→};
528→
529→export type TestUserWithMcp = TestUser & {
530→  /** @deprecated Use mcpFetch instead — static Bearer headers are rejected by DPoP endpoints. */
531→  mcpHeaders: Record<string, string>;
532→  /** DPoP-protected fetch for MCP endpoints. Creates fresh proof per request. */
533→  mcpFetch: (path: string, options?: { method?: string; body?: unknown }) => Promise<Response>;
534→  accessToken: string;
535→  keyPair: DPoPKeyPair;
536→  workspaceId: string;
537→  identityId: string;
538→};
539→
540→/**
541→ * Create a test user with DPoP-bound token for MCP endpoints.
542→ * Generates key pair, creates identity, seeds broad-access intent, acquires token.
543→ */
544→export async function createTestUserWithMcp(
545→  baseUrl: string,
546→  surreal: Surreal,
547→  suffix: string,
548→  options?: { workspaceId?: string },
549→): Promise<TestUserWithMcp> {
550→  const user = await createTestUser(baseUrl, suffix);
551→
552→  // Generate DPoP key pair
553→  const keyPair = await generateDPoPKeyPair();
554→
555→  // Use provided workspace or create a new one for this test identity
556→  const workspaceId = options?.workspaceId ?? `test-workspace-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
557→  const workspaceRecord = new RecordId("workspace", workspaceId);
558→  if (!options?.workspaceId) {
559→    await surreal.query(`CREATE $workspace CONTENT $content;`, {
560→      workspace: workspaceRecord,
561→      content: {
562→        name: `Test Workspace ${suffix}`,
563→        status: "active",
564→        onboarding_complete: true,
565→        onboarding_turn_count: 0,
566→        onboarding_summary_pending: false,
567→        onboarding_started_at: new Date(),
568→        created_at: new Date(),
569→      },
570→    });
571→  }
572→
573→  // Create identity record for this user
574→  const identityId = `test-identity-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
575→  const identityRecord = new RecordId("identity", identityId);
576→
577→  await surreal.query(`CREATE $identity CONTENT $content;`, {
578→    identity: identityRecord,
579→    content: {
580→      name: `Test User ${suffix}`,
581→      type: "agent",
582→      workspace: workspaceRecord,
583→      identity_status: "active",
584→      created_at: new Date(),
585→    },
586→  });
587→
588→  // Create member_of edge linking identity to workspace (required by DPoP middleware workspace lookup)
589→  await surreal.query(`RELATE $identity->member_of->$workspace SET added_at = time::now();`, {
590→    identity: identityRecord,
591→    workspace: workspaceRecord,
592→  });
593→
594→  // Create identity_person edge (required by session-based identity resolution in browser-facing routes)
595→  const personRecord = new RecordId("person", user.personId);
596→  await surreal.query(`RELATE $identity->identity_person->$person SET added_at = time::now();`, {
597→    identity: identityRecord,
598→    person: personRecord,
599→  });
600→
601→  // Seed a broad-access authorized intent covering all MCP operations
602→  const broadActions = [
603→    { type: "brain_action", action: "read", resource: "workspace" },
604→    { type: "brain_action", action: "read", resource: "project" },
605→    { type: "brain_action", action: "read", resource: "task" },
606→    { type: "brain_action", action: "read", resource: "decision" },
607→    { type: "brain_action", action: "read", resource: "constraint" },
608→    { type: "brain_action", action: "read", resource: "change_log" },
609→    { type: "brain_action", action: "read", resource: "entity" },
610→    { type: "brain_action", action: "read", resource: "suggestion" },
611→    { type: "brain_action", action: "read", resource: "intent" },
612→    { type: "brain_action", action: "reason", resource: "decision" },
613→    { type: "brain_action", action: "reason", resource: "constraint" },
614→    { type: "brain_action", action: "reason", resource: "commit" },
615→    { type: "brain_action", action: "create", resource: "decision" },
616→    { type: "brain_action", action: "create", resource: "question" },
617→    { type: "brain_action", action: "create", resource: "task" },
618→    { type: "brain_action", action: "create", resource: "note" },
619→    { type: "brain_action", action: "create", resource: "observation" },
620→    { type: "brain_action", action: "create", resource: "suggestion" },
621→    { type: "brain_action", action: "create", resource: "session" },
622→    { type: "brain_action", action: "create", resource: "commit" },
623→    { type: "brain_action", action: "create", resource: "intent" },
624→    { type: "brain_action", action: "update", resource: "task" },
625→    { type: "brain_action", action: "update", resource: "session" },
626→    { type: "brain_action", action: "update", resource: "suggestion" },
627→    { type: "brain_action", action: "submit", resource: "intent" },
628→  ];
629→
630→  const intentId = `test-intent-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
631→  const intentRecord = new RecordId("intent", intentId);
632→  const traceRecord = new RecordId("trace", `trace-${intentId}`);
633→
634→  await surreal.query(`CREATE $trace CONTENT $traceContent;`, {
635→    trace: traceRecord,
636→    traceContent: { type: "intent_submission", actor: identityRecord, workspace: workspaceRecord, created_at: new Date() },
637→  });
638→
639→  await surreal.query(`CREATE $intent CONTENT $content;`, {
640→    intent: intentRecord,
641→    content: {
642→      goal: "Broad test access",
643→      reasoning: "Pre-authorized for acceptance testing",
644→      status: "authorized",
645→      priority: 50,
646→      authorization_details: broadActions,
647→      dpop_jwk_thumbprint: keyPair.thumbprint,
648→      action_spec: { provider: "test", action: "broad_access", params: {} },
649→      trace_id: traceRecord,
650→      requester: identityRecord,
651→      workspace: workspaceRecord,
652→      evaluation: {
653→        decision: "APPROVE",
654→        risk_score: 0,
655→        reason: "Pre-authorized for testing",
656→        evaluated_at: new Date(),
657→        policy_only: true,
658→      },
659→      created_at: new Date(),
660→    },
661→  });
662→
663→  // Request DPoP-bound access token from Custom AS
664→  const tokenUri = `${baseUrl}/api/auth/token`;
665→  const dpopProof = await createDPoPProof(keyPair, "POST", tokenUri);
666→
667→  const tokenRes = await fetch(tokenUri, {
668→    method: "POST",
669→    headers: {
670→      "Content-Type": "application/json",
671→      DPoP: dpopProof,
672→    },
673→    body: JSON.stringify({
674→      grant_type: "urn:brain:intent-authorization",
675→      intent_id: intentId,
676→      authorization_details: broadActions,
677→    }),
678→  });
679→
680→  if (!tokenRes.ok) {
681→    const body = await tokenRes.text();
682→    throw new Error(`DPoP token acquisition failed (${tokenRes.status}): ${body}`);
683→  }
684→
685→  const { access_token } = (await tokenRes.json()) as { access_token: string };
686→
687→  const mcpFetch = async (path: string, options?: { method?: string; body?: unknown }): Promise<Response> => {
688→    const method = options?.method ?? "POST";
689→    const requestUri = `${baseUrl}${path}`;
690→    const proof = await createDPoPProof(keyPair, method, requestUri);
691→
692→    return fetch(requestUri, {
693→      method,
694→      headers: {
695→        "Content-Type": "application/json",
696→        Authorization: `DPoP ${access_token}`,
697→        DPoP: proof,
698→      },
699→      body: method === "GET" || method === "HEAD"
700→        ? undefined
701→        : (options?.body !== undefined ? JSON.stringify(options.body) : JSON.stringify({})),
702→    });
703→  };
704→
705→  return {
706→    ...user,
707→    mcpHeaders: { Authorization: `DPoP ${access_token}` },
708→    mcpFetch,
709→    accessToken: access_token,
710→    keyPair,
711→    workspaceId,
712→    identityId,
713→  };
714→}
715→
716→// ---------------------------------------------------------------------------
717→// DPoP Helpers
718→// ---------------------------------------------------------------------------
719→
720→async function generateDPoPKeyPair(): Promise<DPoPKeyPair> {
721→  const { publicKey, privateKey } = await crypto.subtle.generateKey(
722→    { name: "ECDSA", namedCurve: "P-256" },
723→    true,
724→    ["sign", "verify"],
725→  );
726→
727→  const publicJwk = await crypto.subtle.exportKey("jwk", publicKey);
728→  const thumbprint = await computeDPoPThumbprint(publicJwk);
729→
730→  return { privateKey, publicKey, publicJwk, thumbprint };
731→}
732→
733→async function computeDPoPThumbprint(publicJwk: JsonWebKey): Promise<string> {
734→  const thumbprintInput = JSON.stringify({
735→    crv: publicJwk.crv,
736→    kty: publicJwk.kty,
737→    x: publicJwk.x,
738→    y: publicJwk.y,
739→  });
740→
741→  const hashBuffer = await crypto.subtle.digest(
742→    "SHA-256",
743→    new TextEncoder().encode(thumbprintInput),
744→  );
745→
746→  return base64urlBytes(new Uint8Array(hashBuffer));
747→}
748→
749→async function createDPoPProof(
750→  keyPair: DPoPKeyPair,
751→  method: string,
752→  targetUri: string,
753→): Promise<string> {
754→  const header = {
755→    typ: "dpop+jwt" as const,
756→    alg: "ES256" as const,
757→    jwk: {
758→      kty: keyPair.publicJwk.kty,
759→      crv: keyPair.publicJwk.crv,
760→      x: keyPair.publicJwk.x,
761→      y: keyPair.publicJwk.y,
762→    },
763→  };
764→
765→  const payload = {
766→    jti: crypto.randomUUID(),
767→    htm: method,
768→    htu: targetUri,
769→    iat: Math.floor(Date.now() / 1000),
770→  };
771→
772→  const importedKey = await jose.importJWK(
773→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
774→    "ES256",
775→  );
776→
777→  return await new jose.SignJWT(payload)
778→    .setProtectedHeader(header)
779→    .sign(importedKey);
780→}
781→
782→function base64urlBytes(bytes: Uint8Array): string {
783→  const binary = String.fromCharCode(...bytes);
784→  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=/g, "");
785→}
786→
787→// ---------------------------------------------------------------------------
788→// Internal Utilities
789→// ---------------------------------------------------------------------------
790→
791→function requireTestEnv(name: string): string {
792→  const value = process.env[name];
793→  if (!value || value.trim().length === 0) {
794→    throw new Error(`Acceptance test requires env var ${name}`);
795→  }
796→  return value;
797→}
798→
799→async function withTimeout<T>(callback: () => Promise<T>, timeoutMs: number, label: string): Promise<T> {
800→  return await Promise.race([
801→    callback(),
802→    new Promise<T>((_, reject) => {
803→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
804→    }),
805→  ]);
806→}
