/**
 * Split SQL into statements respecting `{...}` block nesting.
 * DEFINE FUNCTION / DEFINE EVENT bodies contain semicolons that are NOT
 * statement terminators. Naively splitting on `;` breaks those bodies into
 * orphaned fragments that corrupt the batch query.
 */
function splitSqlStatements(sql: string): string[] {
  const stmts: string[] = [];
  let current = "";
  let depth = 0;
  for (let i = 0; i < sql.length; i++) {
    const ch = sql[i];
    if (ch === "{") depth++;
    else if (ch === "}") depth--;

    if (ch === ";" && depth === 0) {
      const trimmed = current.trim();
      if (trimmed.length > 0) stmts.push(trimmed);
      current = "";
    } else {
      current += ch;
    }
  }
  const trimmed = current.trim();
  if (trimmed.length > 0) stmts.push(trimmed);
  return stmts;
}

/**
 * Apply the base schema to a SurrealDB instance.
 *
 * DEFINE ANALYZER cannot run inside a transaction in SurrealDB v3.0+.
 * The SDK may treat a multi-statement .query() as an implicit transaction,
 * causing the analyzer and dependent FULLTEXT indexes to fail silently.
 *
 * We split the schema into three phases:
 * 1. DEFINE ANALYZER (must run outside any transaction)
 * 2. Schema definitions (DEFINE TABLE/FIELD/INDEX) — batch is fine
 * 3. Seed data (CREATE statements) — separate batch to isolate from index errors
 */
export async function applyTestSchema(surreal: Surreal): Promise<void> {
  const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");

  // Strip full-line comments before splitting — comments may contain semicolons
  // (e.g. "-- The edge is the source of truth; status is a derived consequence.")
  // which would create spurious fragments after the split.
  const withoutComments = schemaSql
    .split("\n")
    .filter((line) => !line.trimStart().startsWith("--"))
    .join("\n");

  // Brace-aware split: only split on `;` outside `{...}` blocks.
  // DEFINE FUNCTION and DEFINE EVENT bodies contain semicolons that must not
  // be treated as statement terminators.
  const statements = splitSqlStatements(withoutComments);

  // Phase 1: DEFINE ANALYZER (must be isolated)
  const analyzerStmts = statements.filter((s) => s.startsWith("DEFINE ANALYZER"));
  for (const stmt of analyzerStmts) {
    await surreal.query(stmt + ";");
  }

  // Phase 2: Schema definitions (DEFINE TABLE/FIELD/INDEX/FUNCTION/EVENT)
  const schemaStmts = statements.filter(
    (s) => !s.startsWith("DEFINE ANALYZER") && !s.startsWith("CREATE"),
  );
  if (schemaStmts.length > 0) {
    await surreal.query(schemaStmts.map((s) => s + ";").join("\n"));
  }

  // Phase 3: Seed data (CREATE statements) — isolated so index issues don't block seeds
  const seedStmts = statements.filter((s) => s.startsWith("CREATE"));
  if (seedStmts.length > 0) {
    await surreal.query(seedStmts.map((s) => s + ";").join("\n"));
  }
}

export function setupAcceptanceSuite(
  suiteName: string,
  options?: AcceptanceSuiteOptions,
): () => AcceptanceTestRuntime {
  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
  const namespace = `accept_${runId}`;
  const suiteSlug = suiteName
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "");
  const database = `${suiteSlug || "suite"}_${Math.floor(Math.random() * 100000)}`;

  let runtime: AcceptanceTestRuntime | undefined;
  let server: ReturnType<typeof Bun.serve> | undefined;
  let runtimeSurreal: Surreal | undefined;
  let analyticsSurreal: Surreal | undefined;
  let inflight: InflightTracker | undefined;
  let setupSucceeded = false;

  beforeAll(async () => {
    const surreal = new Surreal();
    await withTimeout(() => surreal.connect(surrealUrl), 10_000, "connect to SurrealDB");
    await withTimeout(
      () => surreal.signin({ username: surrealUsername, password: surrealPassword }),
      10_000,
      "authenticate with SurrealDB",
    );

    await withTimeout(() => surreal.query(`DEFINE NAMESPACE ${namespace};`), 10_000, "define test namespace");
    await withTimeout(() => surreal.use({ namespace }), 10_000, "switch to test namespace");
    await withTimeout(() => surreal.query(`DEFINE DATABASE ${database};`), 10_000, "define test database");
    await withTimeout(
      () => surreal.use({ namespace, database }),
      10_000,
      "switch to test namespace/database",
    );

    await withTimeout(() => applyTestSchema(surreal), 20_000, "apply schema");

    // Reserve a port so betterAuth gets the real URL at init time
    const tempServer = Bun.serve({ port: 0, fetch: () => new Response() });
    const reservedPort = tempServer.port;
    tempServer.stop(true);
    const baseUrl = `http://127.0.0.1:${reservedPort}`;

    const config: ServerConfig = {
      openRouterApiKey: requireTestEnv("OPENROUTER_API_KEY"),
      chatAgentModelId: requireTestEnv("CHAT_AGENT_MODEL"),
      extractionModelId: requireTestEnv("EXTRACTION_MODEL"),
      pmAgentModelId: process.env.PM_AGENT_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
      analyticsAgentModelId: requireTestEnv("ANALYTICS_MODEL"),
      embeddingModelId: requireTestEnv("EMBEDDING_MODEL"),
      embeddingDimension: Number(requireTestEnv("EMBEDDING_DIMENSION")),
      extractionStoreThreshold: Number(requireTestEnv("EXTRACTION_STORE_THRESHOLD")),
      extractionDisplayThreshold: Number(requireTestEnv("EXTRACTION_DISPLAY_THRESHOLD")),
      surrealUrl,
      surrealUsername,
      surrealPassword,
      surrealNamespace: namespace,
      surrealDatabase: database,
      port: reservedPort,
      betterAuthSecret: process.env.BETTER_AUTH_SECRET ?? "smoke-test-secret-at-least-32-chars-long",
      betterAuthUrl: baseUrl,
      githubClientId: process.env.GITHUB_CLIENT_ID ?? "smoke-test-github-id",
      githubClientSecret: process.env.GITHUB_CLIENT_SECRET ?? "smoke-test-github-secret",
      observerModelId: process.env.OBSERVER_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
      scorerModelId: process.env.SCORER_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
      anthropicApiUrl: process.env.ANTHROPIC_API_URL?.trim() || "https://api.anthropic.com",
      ...(process.env.ANTHROPIC_API_KEY?.trim() ? { anthropicApiKey: process.env.ANTHROPIC_API_KEY.trim() } : {}),
      inferenceProvider: "openrouter",
      selfHosted: false,
      worktreeManagerEnabled: false,
      baseUrl: baseUrl,
      orchestratorMockAgent: false,
      ...options?.configOverrides,
    };

    const deps = await createRuntimeDependencies(config);
    runtimeSurreal = deps.surreal;
    analyticsSurreal = deps.analyticsSurreal;
    inflight = createInflightTracker();

    const serverDeps: ServerDependencies = {
      config,
      surreal: deps.surreal,
      analyticsSurreal: deps.analyticsSurreal,
      auth: deps.auth,
      chatAgentModel: deps.chatAgentModel,
      extractionModel: deps.extractionModel,
      pmAgentModel: deps.pmAgentModel,
      analyticsAgentModel: deps.analyticsAgentModel,
      embeddingModel: deps.embeddingModel,
      observerModel: deps.observerModel,
      scorerModel: deps.scorerModel,
      sse: createSseRegistry(),
      inflight,
      asSigningKey: deps.asSigningKey,
      nonceCache: createNonceCache(),
      mcpClientFactory: options?.mcpClientFactoryOverride ?? createMcpClientFactory(),
      sandboxAgentAdapter: deps.sandboxAgentAdapter,
    };
    destroySandbox = deps.destroySandbox;

    server = createBrainServer(serverDeps);
    const port = server.port;

    // Start reactive coordination layer: LIVE SELECT -> Feed SSE Bridge -> SSE Registry
    const liveSelectManager = createLiveSelectManager({ surreal: deps.surreal });
    const feedSseBridge = createFeedSseBridge({
      liveSelectManager,
      sseRegistry: serverDeps.sse,
    });
    feedSseBridge.subscribeAll();

    // Agent Coordinator is created inside createBrainServer (called above).
    // In prod, DEFINE EVENT webhooks call the coordinator endpoint.
    // In acceptance tests, observations trigger the coordinator via the same HTTP endpoint.

    inflight.track(
      liveSelectManager.start().catch(() => undefined),
    );

    runtime = { baseUrl, surreal, namespace, database, port };
    setupSucceeded = true;
  }, 60_000);

  let destroySandbox: (() => Promise<void>) | undefined;

  afterAll(async () => {
    // Drain fire-and-forget work (e.g. webhook extraction) before closing DB
    if (inflight) {
      await inflight.drain(15_000);
    }

    if (server) {
      server.stop(true);
    }

    // Destroy SandboxAgent embedded server if started
    if (destroySandbox) {
      await destroySandbox().catch(() => undefined);
    }

    if (runtimeSurreal) {
      await runtimeSurreal.close().catch(() => undefined);
    }
    if (analyticsSurreal) {
      await analyticsSurreal.close().catch(() => undefined);
    }

    if (!runtime) {
      return;
    }

    if (setupSucceeded && !process.env.SMOKE_KEEP_DB) {
      try {
        await withTimeout(() => runtime!.surreal.query(`REMOVE DATABASE ${database};`), 10_000, "remove test database");
      } catch {
        // Best effort cleanup.
      }

      try {
        await withTimeout(() => runtime!.surreal.query(`REMOVE NAMESPACE ${namespace};`), 10_000, "remove test namespace");
      } catch {
        // Best effort cleanup.
      }
    }

    await withTimeout(() => runtime!.surreal.close(), 2_000, "close SurrealDB").catch(() => undefined);
  }, 20_000);

  return () => {
    if (!runtime) {
      throw new Error("Acceptance runtime requested before suite setup completed");
    }
    return runtime;
  };
}

