  1→/**
  2→ * Sandbox Agent Adapter -- port types and adapter factories.
  3→ *
  4→ * Port types define the contract for interacting with a SandboxAgent server.
  5→ * The adapter abstracts at the SDK level: one factory wraps the real SDK instance,
  6→ * another provides a test-injectable mock with overridable behavior.
  7→ *
  8→ * Real SDK types are re-exported for use by callers without direct SDK dependency.
  9→ */
 10→import type {
 11→  SandboxAgent,
 12→  Session,
 13→  SessionCreateRequest,
 14→  SessionEvent,
 15→  SessionEventListener,
 16→  SessionPermissionRequest,
 17→  PermissionRequestListener,
 18→  PermissionReply,
 19→} from "sandbox-agent";
 20→import type { PromptRequest, PromptResponse } from "sandbox-agent";
 21→
 22→// Re-export SDK types used at port boundaries
 23→export type {
 24→  SessionEvent,
 25→  SessionEventListener,
 26→  SessionPermissionRequest,
 27→  PermissionRequestListener,
 28→  PermissionReply,
 29→  PromptResponse,
 30→};
 31→
 32→// ── Port Types ──
 33→
 34→/**
 35→ * Thin wrapper around the SDK's Session, exposing only the methods Brain needs.
 36→ * Keeps the port boundary narrow -- callers never depend on the full Session class.
 37→ */
 38→export type SessionHandle = {
 39→  id: string;
 40→  prompt: (
 41→    messages: PromptRequest["prompt"],
 42→  ) => Promise<PromptResponse>;
 43→  onEvent: (listener: SessionEventListener) => () => void;
 44→  onPermissionRequest: (listener: PermissionRequestListener) => () => void;
 45→  respondPermission: (permissionId: string, reply: PermissionReply) => Promise<void>;
 46→};
 47→
 48→export type SandboxAgentAdapter = {
 49→  createSession: (request: SessionCreateRequest) => Promise<SessionHandle>;
 50→  resumeSession: (sessionId: string) => Promise<SessionHandle>;
 51→  destroySession: (sessionId: string) => Promise<void>;
 52→};
 53→
 54→// ── Production Adapter Factory ──
 55→
 56→function wrapSession(session: Session): SessionHandle {
 57→  return {
 58→    id: session.id,
 59→    prompt: (messages) => session.prompt(messages),
 60→    onEvent: (listener) => session.onEvent(listener),
 61→    onPermissionRequest: (listener) => session.onPermissionRequest(listener),
 62→    respondPermission: (permissionId, reply) => session.respondPermission(permissionId, reply),
 63→  };
 64→}
 65→
 66→/**
 67→ * Creates a production adapter backed by a real SandboxAgent SDK instance.
 68→ * The SDK instance should be created via `SandboxAgent.start()` or `SandboxAgent.connect()`.
 69→ */
 70→export function createSandboxAgentAdapter(
 71→  sdk: SandboxAgent,
 72→): SandboxAgentAdapter {
 73→  return {
 74→    createSession: async (request) => {
 75→      const session = await sdk.createSession(request);
 76→      return wrapSession(session);
 77→    },
 78→    resumeSession: async (sessionId) => {
 79→      const session = await sdk.resumeSession(sessionId);
 80→      return wrapSession(session);
 81→    },
 82→    destroySession: async (sessionId) => {
 83→      await sdk.destroySession(sessionId);
 84→    },
 85→  };
 86→}
 87→
 88→// ── Mock Adapter Factory ──
 89→
 90→export function createMockAdapter(
 91→  overrides?: Partial<SandboxAgentAdapter>,
 92→): SandboxAgentAdapter {
 93→  const sessions = new Map<string, SessionHandle>();
 94→  const destroyed = new Set<string>();
 95→
 96→  const createHandle = (id: string): SessionHandle => ({
 97→    id,
 98→    prompt: async () => {
 99→      if (destroyed.has(id)) {
100→        throw new Error(`Session ${id} has been destroyed`);
101→      }
102→      return { stopReason: "end_turn" as const } as PromptResponse;
103→    },
104→    onEvent: () => () => {},
105→    onPermissionRequest: () => () => {},
106→    respondPermission: async () => {
107→      if (destroyed.has(id)) {
108→        throw new Error(`Session ${id} has been destroyed`);
109→      }
110→    },
111→  });
112→
113→  return {
114→    createSession: async (request) => {
115→      const id = `session-${crypto.randomUUID()}`;
116→      const handle = createHandle(id);
117→      sessions.set(id, handle);
118→      return handle;
119→    },
120→    resumeSession: async (sessionId) => {
121→      if (destroyed.has(sessionId)) {
122→        throw new Error(`Session ${sessionId} has been destroyed`);
123→      }
124→      const existing = sessions.get(sessionId);
125→      if (existing) {
126→        return existing;
127→      }
128→      const handle = createHandle(sessionId);
129→      sessions.set(sessionId, handle);
130→      return handle;
131→    },
132→    destroySession: async (sessionId) => {
133→      sessions.delete(sessionId);
134→      destroyed.add(sessionId);
135→    },
136→    ...overrides,
137→  };
138→}
139→

  1→/**
  2→ * Sandbox event bridge: transforms SandboxAgent SessionEvents into Brain
  3→ * StreamEvent variants and forwards them to the SSE registry.
  4→ *
  5→ * Pure transform function (translateSessionEvent) + effectful bridge handle
  6→ * (createSandboxEventBridge) that manages the event forwarding lifecycle.
  7→ *
  8→ * SessionEvent.payload is an ACP JSON-RPC message. The bridge extracts
  9→ * session/update notifications and maps their content to Brain stream events.
 10→ *
 11→ * This module handles SandboxAgent events (different schema from event-bridge.ts
 12→ * which handles Claude SDK messages). Both coexist until R1 migration completes.
 13→ */
 14→import type {
 15→  AgentTokenEvent,
 16→  AgentStatusEvent,
 17→  StreamEvent,
 18→} from "../../shared/contracts";
 19→import type { SessionEvent } from "./sandbox-adapter";
 20→import { log } from "../telemetry/logger";
 21→
 22→// Re-export for callers that reference the old SandboxEvent name
 23→export type SandboxEvent = SessionEvent;
 24→
 25→// ---------------------------------------------------------------------------
 26→// Port: dependencies as function signatures
 27→// ---------------------------------------------------------------------------
 28→
 29→export type SandboxEventBridgeDeps = {
 30→  emitEvent: (streamId: string, event: StreamEvent) => void;
 31→  updateLastEventAt: (sessionId: string) => Promise<void>;
 32→  notifyStallDetector: (sessionId: string) => void;
 33→};
 34→
 35→// ---------------------------------------------------------------------------
 36→// Bridge handle
 37→// ---------------------------------------------------------------------------
 38→
 39→export type SandboxEventBridgeHandle = {
 40→  handleEvent: (event: SessionEvent) => void;
 41→  stop: () => void;
 42→};
 43→
 44→// ---------------------------------------------------------------------------
 45→// ACP JSON-RPC payload helpers (untyped extraction from AnyMessage)
 46→// ---------------------------------------------------------------------------
 47→
 48→type AcpPayload = {
 49→  method?: string;
 50→  params?: {
 51→    sessionId?: string;
 52→    update?: {
 53→      sessionUpdate?: string;
 54→      content?: { type?: string; text?: string };
 55→      toolCallId?: string;
 56→      name?: string;
 57→      [key: string]: unknown;
 58→    };
 59→    [key: string]: unknown;
 60→  };
 61→  result?: unknown;
 62→  error?: unknown;
 63→  [key: string]: unknown;
 64→};
 65→
 66→function extractSessionUpdate(payload: AcpPayload): { sessionUpdate: string; [key: string]: unknown } | undefined {
 67→  if (payload.method === "session/update" && payload.params?.update) {
 68→    return payload.params.update as { sessionUpdate: string; [key: string]: unknown };
 69→  }
 70→  return undefined;
 71→}
 72→
 73→// ---------------------------------------------------------------------------
 74→// Pure transform: SessionEvent -> StreamEvent | undefined
 75→// ---------------------------------------------------------------------------
 76→
 77→function translateToolCall(
 78→  sessionId: string,
 79→  update: { name?: string; toolCallId?: string; [key: string]: unknown },
 80→): AgentTokenEvent {
 81→  const toolName = (update.name as string) ?? "unknown";
 82→  return {
 83→    type: "agent_token",
 84→    sessionId,
 85→    token: `Tool Call: ${toolName}`,
 86→  };
 87→}
 88→
 89→function translateMessageChunk(
 90→  sessionId: string,
 91→  update: { content?: { text?: string }; [key: string]: unknown },
 92→): AgentTokenEvent | undefined {
 93→  const text = update.content?.text;
 94→  if (!text) return undefined;
 95→  return {
 96→    type: "agent_token",
 97→    sessionId,
 98→    token: text,
 99→  };
100→}
101→
102→export function translateSessionEvent(
103→  event: SessionEvent,
104→): StreamEvent | undefined {
105→  const payload = event.payload as AcpPayload;
106→  const update = extractSessionUpdate(payload);
107→
108→  if (!update) {
109→    // Not a session/update notification -- may be a response or other message.
110→    // Check if it's a prompt response (which has result.stopReason)
111→    if (payload.result && typeof payload.result === "object") {
112→      const result = payload.result as { stopReason?: string };
113→      if (result.stopReason) {
114→        return {
115→          type: "agent_status",
116→          sessionId: event.sessionId,
117→          status: "completed" as AgentStatusEvent["status"],
118→        };
119→      }
120→    }
121→    return undefined;
122→  }
123→
124→  switch (update.sessionUpdate) {
125→    case "tool_call":
126→      return translateToolCall(event.sessionId, update);
127→
128→    case "agent_message_chunk":
129→    case "user_message_chunk":
130→    case "agent_thought_chunk":
131→      return translateMessageChunk(event.sessionId, update);
132→
133→    default:
134→      // Other update types (plan, config_option_update, etc.) are informational
135→      // and don't map to Brain stream events yet.
136→      return undefined;
137→  }
138→}
139→
140→// Backwards-compatible alias
141→export const translateSandboxEvent = translateSessionEvent;
142→
143→// ---------------------------------------------------------------------------
144→// Bridge handle factory
145→// ---------------------------------------------------------------------------
146→
147→export function createSandboxEventBridge(
148→  deps: SandboxEventBridgeDeps,
149→  streamId: string,
150→  sessionId: string,
151→): SandboxEventBridgeHandle {
152→  let stopped = false;
153→
154→  const handleEvent = (event: SessionEvent): void => {
155→    if (stopped) return;
156→
157→    const streamEvent = translateSessionEvent(event);
158→    if (!streamEvent) return;
159→
160→    deps.emitEvent(streamId, streamEvent);
161→
162→    // Fire-and-forget: update last_event_at for stall detection
163→    deps.updateLastEventAt(sessionId).catch((err) => {
164→      log.warn("sandbox-event-bridge", "Failed to update last_event_at", {
165→        sessionId,
166→        error: String(err),
167→      });
168→    });
169→
170→    // Notify stall detector of activity
171→    deps.notifyStallDetector(sessionId);
172→  };
173→
174→  return {
175→    handleEvent,
176→    stop(): void {
177→      stopped = true;
178→    },
179→  };
180→}
181→

 1→// ---------------------------------------------------------------------------
 2→// Agent spawn configuration and options builder
 3→// ---------------------------------------------------------------------------
 4→
 5→export type AgentSpawnConfig = {
 6→  prompt: string;
 7→  workDir: string;
 8→  workspaceId: string;
 9→  brainBaseUrl: string;
10→  brainIdentityId?: string;
11→  brainEnv?: Record<string, string>;
12→  anthropicBaseUrl?: string;
13→  anthropicCustomHeaders?: string;
14→};
15→
16→export function resolveBrainCliCommand(): string {
17→  return "brain";
18→}
19→
20→// ---------------------------------------------------------------------------
21→// buildAgentOptions — pure function mapping config to SDK query params
22→// ---------------------------------------------------------------------------
23→
24→const ALLOWED_TOOLS = [
25→  "Read",
26→  "Edit",
27→  "Write",
28→  "Bash",
29→  "Glob",
30→  "Grep",
31→] as const;
32→
33→const MAX_TURNS = 200;
34→
35→export function buildAgentOptions(
36→  config: AgentSpawnConfig,
37→  abortController?: AbortController,
38→): { prompt: string; options: Record<string, unknown> } {
39→  const brainCommand = resolveBrainCliCommand();
40→  const brainMcpPathOverride = process.env.BRAIN_MCP_PATH_OVERRIDE;
