  1→import { createOpenRouter } from "@openrouter/ai-sdk-provider";
  2→import { createOllama } from "ollama-ai-provider";
  3→import { wrapLanguageModel } from "ai";
  4→import { devToolsMiddleware } from "@ai-sdk/devtools";
  5→import { Surreal } from "surrealdb";
  6→import type { ServerConfig } from "./config";
  7→import { createAuth, type Auth } from "../auth/config";
  8→import { bootstrapSigningKeyFromSurreal, type AsSigningKey } from "../oauth/as-key-management";
  9→import { createMcpClientFactory, type McpClientFactory } from "../tool-registry/mcp-client";
 10→import type { SandboxAgent } from "sandbox-agent";
 11→import type { SandboxAgentAdapter } from "../orchestrator/sandbox-adapter";
 12→
 13→const devtools = process.env.AI_DEVTOOLS === "1" ? devToolsMiddleware() : undefined;
 14→
 15→export async function createRuntimeDependencies(config: ServerConfig): Promise<{
 16→  surreal: Surreal;
 17→  analyticsSurreal: Surreal;
 18→  auth: Auth;
 19→  chatAgentModel: any;
 20→  extractionModel: any;
 21→  pmAgentModel: any;
 22→  analyticsAgentModel: any;
 23→  observerModel: any;
 24→  scorerModel: any;
 25→  asSigningKey: AsSigningKey;
 26→  mcpClientFactory: McpClientFactory;
 27→}> {
 28→  const surreal = new Surreal();
 29→  await surreal.connect(config.surrealUrl);
 30→  await surreal.signin({ username: config.surrealUsername, password: config.surrealPassword });
 31→  await surreal.use({ namespace: config.surrealNamespace, database: config.surrealDatabase });
 32→
 33→  const analyticsSurreal = new Surreal();
 34→  await analyticsSurreal.connect(config.surrealUrl);
 35→  await analyticsSurreal.signin({
 36→    namespace: config.surrealNamespace,
 37→    database: config.surrealDatabase,
 38→    username: "analytics",
 39→    password: "brain-analytics-readonly",
 40→  });
 41→  await analyticsSurreal.use({ namespace: config.surrealNamespace, database: config.surrealDatabase });
 42→
 43→  const wrap = (model: any) => devtools ? wrapLanguageModel({ model, middleware: devtools }) : model;
 44→
 45→  const { chatAgentModel, extractionModel, pmAgentModel, analyticsAgentModel, observerModel, scorerModel } =
 46→    config.inferenceProvider === "ollama"
 47→      ? createOllamaModels(config, wrap)
 48→      : createOpenRouterModels(config, wrap);
 49→
 50→  const auth = createAuth(surreal, {
 51→    betterAuthSecret: config.betterAuthSecret,
 52→    betterAuthUrl: config.betterAuthUrl,
 53→    githubClientId: config.githubClientId,
 54→    githubClientSecret: config.githubClientSecret,
 55→    selfHosted: config.selfHosted,
 56→  });
 57→
 58→  const asSigningKey = await bootstrapSigningKeyFromSurreal(surreal);
 59→  const mcpClientFactory = createMcpClientFactory();
 60→
 61→  // SandboxAgent SDK — start embedded server when enabled
 62→  let sandboxAgentAdapter: SandboxAgentAdapter | undefined;
 63→  let destroySandbox: (() => Promise<void>) | undefined;
 64→  if (config.sandboxAgentEnabled) {
 65→    const { SandboxAgent: SandboxAgentClass } = await import("sandbox-agent");
 66→    const { local } = await import("sandbox-agent/local");
 67→    const { createSandboxAgentAdapter } = await import("../orchestrator/sandbox-adapter");
 68→    const sdk = await SandboxAgentClass.start({ sandbox: local() });
 69→    sandboxAgentAdapter = createSandboxAgentAdapter(sdk);
 70→    destroySandbox = () => sdk.destroySandbox();
 71→  }
 72→
 73→  return {
 74→    surreal,
 75→    analyticsSurreal,
 76→    auth,
 77→    chatAgentModel,
 78→    extractionModel,
 79→    pmAgentModel,
 80→    analyticsAgentModel,
 81→    observerModel,
 82→    scorerModel,
 83→    asSigningKey,
 84→    mcpClientFactory,
 85→    sandboxAgentAdapter,
 86→    destroySandbox,
 87→  };
 88→}
