270→type SessionLookup =
271→  | { ok: true; session: SessionRow; record: RecordId<"agent_session", string>; status: OrchestratorStatus }
272→  | { ok: false; error: SessionError };
273→
274→async function lookupSession(
275→  surreal: Surreal,
276→  sessionId: string,
277→): Promise<SessionLookup> {
278→  const record = new RecordId("agent_session", sessionId);
279→  const session = await surreal.select<SessionRow>(record);
280→  if (!session) {
281→    return { ok: false, error: sessionNotFound(sessionId) };
282→  }
283→  if (!session.orchestrator_status) {
284→    throw new Error(`agent_session ${sessionId} missing orchestrator_status — data corruption`);
285→  }
286→  const status = session.orchestrator_status as OrchestratorStatus;
287→  return { ok: true, session, record, status };
288→}
