340→// createOrchestratorSession
341→// ---------------------------------------------------------------------------
342→
343→type CreateSessionInput = {
344→  surreal: Surreal;
345→  shellExec: ShellExec;
346→  brainBaseUrl: string;
347→  brainIdentityId?: string;
348→  brainEnv?: Record<string, string>;
349→  anthropicBaseUrl?: string;
350→  anthropicCustomHeaders?: string;
351→  workspaceId: string;
352→  taskId: string;
353→  intentId?: string;
354→  authToken?: string;
355→  spawnAgent?: SpawnAgentFn;
356→  adapter?: SandboxAgentAdapter;
357→  sandboxAgentType?: string;
358→  validateAssignment: (
359→    surreal: Surreal,
360→    workspaceId: string,
361→    taskId: string,
362→  ) => Promise<AssignmentResult>;
363→  createAgentSession: (input: {
364→    surreal: Surreal;
365→    agent: string;
366→    workspaceRecord: RecordId<"workspace", string>;
367→    taskId?: string;
368→  }) => Promise<{ session_id: string }>;
369→};
370→
371→export async function createOrchestratorSession(
372→  input: CreateSessionInput,
373→): Promise<OrchestratorSessionResult> {
374→  // 0. Intent authorization gate (optional — backwards compatible)
375→  if (input.intentId) {
376→    const gateResult = await checkIntentAuthorization(input.surreal, input.intentId, input.workspaceId);
377→    if (!gateResult.ok) {
378→      return { ok: false, error: gateResult.error };
379→    }
380→  }
381→
382→  // 1. Validate assignment eligibility
383→  const assignmentResult = await input.validateAssignment(
384→    input.surreal,
385→    input.workspaceId,
386→    input.taskId,
387→  );
388→
389→  if (!assignmentResult.ok) {
390→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
391→  }
392→
393→  const { validation } = assignmentResult;
394→
395→  // ── Adapter path: delegate to SandboxAgentAdapter ──
396→  if (input.adapter) {
397→    return createSessionViaAdapter(input, validation);
398→  }
399→
400→  // ── Legacy path: worktree + spawn ──
401→  const taskSlug = `${slugFromTitle(validation.title)}-${crypto.randomUUID()}`;
402→  const repoRoot = validation.repoPath;
403→
404→  // 2. Create worktree
405→  const worktreeResult = await createWorktree(
406→    input.shellExec,
407→    repoRoot,
408→    taskSlug,
409→  );
410→
411→  if (!worktreeResult.ok) {
412→    return {
413→      ok: false,
414→      error: worktreeError(worktreeResult.error.message),
415→    };
416→  }
417→
418→  const { branchName, worktreePath } = worktreeResult.value;
419→
420→  // 3. Create agent_session record
421→  const { session_id: agentSessionId } = await input.createAgentSession({
422→    surreal: input.surreal,
423→    agent: "claude-agent-sdk",
424→    workspaceRecord: validation.workspaceRecord,
425→    taskId: input.taskId,
426→  });
427→
428→  const streamId = generateStreamId(agentSessionId);
429→  const anthropicCustomHeaders = input.anthropicCustomHeaders
430→    ? appendOrchestratorProxyHeaders(
431→        input.anthropicCustomHeaders,
432→        input.taskId,
433→        agentSessionId,
434→      )
435→    : undefined;
436→
437→  // 4. Build config and spawn agent
438→  const agentSpawnConfig: AgentSpawnConfig = {
439→    prompt: `/brain-start-task ${input.taskId}`,
440→    workDir: worktreePath,
441→    workspaceId: input.workspaceId,
442→    brainBaseUrl: input.brainBaseUrl,
443→    brainIdentityId: input.brainIdentityId,
444→    brainEnv: input.brainEnv,
445→    anthropicBaseUrl: input.anthropicBaseUrl,
446→    anthropicCustomHeaders,
447→  };
448→
449→  const spawnFn = input.spawnAgent ?? defaultSpawnAgent;
450→  try {
451→    spawnFn(agentSpawnConfig);
452→  } catch (err) {
453→    // Rollback: remove worktree and delete agent_session on spawn failure
454→    await removeWorktree(input.shellExec, repoRoot, branchName);
455→    const sessionRecord = new RecordId("agent_session", agentSessionId);
456→    await input.surreal.delete(sessionRecord);
457→    return {
458→      ok: false,
459→      error: worktreeError(`Failed to spawn agent: ${err instanceof Error ? err.message : String(err)}`),
460→    };
461→  }
462→
463→  // 5. Update agent_session with orchestrator fields
464→  const sessionRecord = new RecordId("agent_session", agentSessionId);
465→  await input.surreal.update(sessionRecord).merge({
466→    orchestrator_status: "spawning" as OrchestratorStatus,
467→    worktree_branch: branchName,
468→    worktree_path: worktreePath,
469→    stream_id: streamId,
470→  });
471→
472→  // 6. Transition intent to executing and create gates relation
473→  if (input.intentId) {
474→    await transitionIntentToExecuting(input.surreal, input.intentId, sessionRecord);
475→  }
476→
477→  return {
478→    ok: true,
479→    value: {
480→      agentSessionId,
481→      streamId,
482→      worktreeBranch: branchName,
483→    },
484→  };
485→}
