755→export async function acceptOrchestratorSession(
756→  input: AcceptSessionInput,
757→): Promise<AcceptSessionResult> {
758→  const lookup = await lookupSession(input.surreal, input.sessionId);
759→  if (!lookup.ok) {
760→    return { ok: false, error: lookup.error };
761→  }
762→  const { session, record: sessionRecord, status } = lookup;
763→
764→  if (!ACCEPTABLE_STATUSES.has(status)) {
765→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
766→  }
767→
768→  const workspaceRecord = requireWorkspace(session, input.sessionId);
769→
770→  // 1. Update orchestrator_status to completed
771→  await input.surreal.update(sessionRecord).merge({
772→    orchestrator_status: "completed" as OrchestratorStatus,
773→  });
774→
775→  // 2. (handle registry eliminated — no cleanup needed)
776→
777→  // 3. End the agent session
778→  await input.endAgentSession({
779→    surreal: input.surreal,
780→    workspaceRecord,
781→    sessionId: input.sessionId,
782→    summary: input.summary,
783→  });
784→
785→  return {
786→    ok: true,
787→    value: {
788→      accepted: true,
789→      sessionId: input.sessionId,
790→    },
791→  };
792→}
