794→// ---------------------------------------------------------------------------
795→// State guard helpers
796→// ---------------------------------------------------------------------------
797→
798→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
799→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
800→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
801→const PROMPTABLE_STATUSES = new Set<OrchestratorStatus>(["spawning", "active", "idle"]);
802→
803→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
804→  return {
805→    code: "SESSION_ERROR",
806→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
807→    httpStatus: 409,
808→  };
809→}
810→
811→function sessionAborted(sessionId: string): SessionError {
812→  return {
813→    code: "SESSION_ERROR",
814→    message: `Session ${sessionId} has been aborted`,
815→    httpStatus: 409,
816→  };
817→}
