819→// ---------------------------------------------------------------------------
820→// getOrchestratorReview
821→// ---------------------------------------------------------------------------
822→
823→type GetReviewInput = {
824→  surreal: Surreal;
825→  sessionId: string;
826→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
827→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
828→  getTaskTitle: (taskId: string) => Promise<string>;
829→};
830→
831→export async function getOrchestratorReview(
832→  input: GetReviewInput,
833→): Promise<ReviewResult> {
834→  const lookup = await lookupSession(input.surreal, input.sessionId);
835→  if (!lookup.ok) {
836→    return { ok: false, error: lookup.error };
837→  }
838→  const { session, status } = lookup;
839→
840→  if (status === "aborted") {
841→    return { ok: false, error: sessionAborted(input.sessionId) };
842→  }
843→
844→  if (!REVIEWABLE_STATUSES.has(status)) {
845→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
846→  }
847→
848→  // Get diff from the branch
849→  const branchName = session.worktree_branch ?? "";
850→  const workspaceRecord = requireWorkspace(session, input.sessionId);
851→  const repoRoot = await input.resolveRepoRoot(workspaceRecord);
852→  const diffResult = await input.getDiff(repoRoot, branchName);
853→
854→  const diff = diffResult.ok
855→    ? diffResult.value
856→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
857→
858→  // Get task title
859→  const taskId = session.task_id ? session.task_id.id : "";
860→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
861→
862→  return {
863→    ok: true,
864→    value: {
865→      taskTitle,
866→      diff,
867→      session: {
868→        orchestratorStatus: status,
869→        ...pickDefined({
870→          worktreeBranch: session.worktree_branch,
871→          startedAt: session.started_at,
872→          lastEventAt: session.last_event_at,
873→        }),
874→      },
875→    },
876→  };
877→}
