879→// ---------------------------------------------------------------------------
880→// rejectOrchestratorSession
881→// ---------------------------------------------------------------------------
882→
883→type RejectSessionInput = {
884→  surreal: Surreal;
885→  sessionId: string;
886→  feedback: string;
887→};
888→
889→export async function rejectOrchestratorSession(
890→  input: RejectSessionInput,
891→): Promise<RejectSessionResult> {
892→  const lookup = await lookupSession(input.surreal, input.sessionId);
893→  if (!lookup.ok) {
894→    return { ok: false, error: lookup.error };
895→  }
896→  const { session, record: sessionRecord, status } = lookup;
897→
898→  if (!REJECTABLE_STATUSES.has(status)) {
899→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
900→  }
901→
902→  // 1. Update session status to active (agent resumes work)
903→  await input.surreal.update(sessionRecord).merge({
904→    orchestrator_status: "active" as OrchestratorStatus,
905→    last_feedback: input.feedback,
906→  });
907→
908→  // 2. Return task to in_progress
909→  if (session.task_id) {
910→    await input.surreal.update(session.task_id).merge({
911→      status: "in_progress",
912→      updated_at: new Date(),
913→    });
914→  }
915→
916→  return {
917→    ok: true,
918→    value: {
919→      rejected: true,
920→      continuing: true,
921→    },
922→  };
923→}
