925→// ---------------------------------------------------------------------------
926→// sendSessionPrompt
927→// ---------------------------------------------------------------------------
928→
929→type SendPromptInput = {
930→  surreal: Surreal;
931→  sessionId: string;
932→  text: string;
933→  adapter?: SandboxAgentAdapter;
934→};
935→
936→export async function sendSessionPrompt(
937→  input: SendPromptInput,
938→): Promise<PromptSessionResult> {
939→  const lookup = await lookupSession(input.surreal, input.sessionId);
940→  if (!lookup.ok) {
941→    return { ok: false, error: lookup.error };
942→  }
943→  const { session, status } = lookup;
944→
945→  if (!PROMPTABLE_STATUSES.has(status)) {
946→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "prompt") };
947→  }
948→
949→  // ── Adapter path: delegate to SandboxAgentAdapter ──
950→  if (input.adapter && session.external_session_id) {
951→    try {
952→      const handle = await input.adapter.resumeSession(session.external_session_id);
953→      await handle.prompt([{ type: "text", text: input.text }]);
954→      return { ok: true, value: { delivered: true } };
955→    } catch (err) {
956→      return {
957→        ok: false,
958→        error: {
959→          code: "SESSION_ERROR",
960→          message: `Failed to deliver prompt: ${err instanceof Error ? err.message : String(err)}`,
961→          httpStatus: 500,
962→        },
963→      };
964→    }
965→  }
966→
967→  // ── Legacy path: Agent SDK does not support follow-up prompts ──
968→  return {
969→    ok: false,
970→    error: {
971→      code: "SESSION_ERROR",
972→      message: `Follow-up prompts are not supported with the Agent SDK. Session ${input.sessionId} runs a single query() conversation.`,
973→      httpStatus: 409,
974→    },
975→  };
976→}
