306→// ---------------------------------------------------------------------------
307→// SSE stream route handler factory
308→// ---------------------------------------------------------------------------
309→
310→export type StreamRouteDeps = {
311→  sseRegistry: SseRegistry;
312→};
313→
314→export function createStreamRouteHandler(deps: StreamRouteDeps) {
315→  const stream: RouteHandler = async (request) => {
316→    const sessionId = request.params.sessionId;
317→
318→    if (!sessionId) {
319→      return jsonError("sessionId is required", 400);
320→    }
321→
322→    const streamId = `stream-${sessionId}`;
323→    return deps.sseRegistry.handleStreamRequest(streamId);
324→  };
325→
326→  return { stream };
327→}
