329→// ---------------------------------------------------------------------------
330→// Wiring factory: creates OrchestratorRouteDeps from server dependencies
331→// ---------------------------------------------------------------------------
332→
333→export type OrchestratorWiringDeps = {
334→  surreal: import("surrealdb").Surreal;
335→  shellExec: import("./worktree-manager").ShellExec;
336→  brainBaseUrl: string;
337→  extractionModel: import("../runtime/types").ServerDependencies["extractionModel"];
338→  asSigningKey: import("../oauth/as-key-management").AsSigningKey;
339→  sseRegistry?: SseRegistry;
340→  queryFn: import("./spawn-agent").QueryFn;
341→  auth: { api: { getSession: (opts: { headers: Headers }) => Promise<{ user?: { id?: string } } | null> } };
342→  mockAgent: boolean;
343→  sandboxAgentAdapter?: import("./sandbox-adapter").SandboxAgentAdapter;
344→  sandboxAgentType?: string;
345→};
346→
347→export function wireOrchestratorRoutes(
348→  wiringDeps: OrchestratorWiringDeps,
349→): {
350→  assign: RouteHandler;
351→  status: RouteHandler;
352→  accept: RouteHandler;
353→  abort: RouteHandler;
354→  review: RouteHandler;
355→  reject: RouteHandler;
356→  prompt: RouteHandler;
357→  stream?: RouteHandler;
358→} {
359→  const proxyTokenTtlDays = readProxyTokenTtlDays();
360→
361→  const issueProxyTokenForWorkspace = async (
362→    workspaceId: string,
363→    authToken: string,
364→  ): Promise<{ proxyToken: string; identityId: string }> => {
365→    const sessionHeaders = new Headers(authToken ? { Cookie: authToken } : undefined);
366→    const session = await wiringDeps.auth.api.getSession({ headers: sessionHeaders });
367→    const personId = session?.user?.id;
368→    if (!personId) {
369→      throw new Error("Failed to issue proxy token: authentication required");
370→    }
371→
372→    const personRecord = new RecordId("person", personId);
373→    const workspaceRecord = new RecordId("workspace", workspaceId);
374→    const [identityRows] = await wiringDeps.surreal.query<[Array<RecordId<"identity", string>>]>(
375→      `SELECT VALUE in FROM member_of WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person) AND out = $ws LIMIT 1;`,
376→      { person: personRecord, ws: workspaceRecord },
377→    );
378→    const identityRecord = identityRows[0];
379→    if (!identityRecord) {
380→      throw new Error(`Failed to issue proxy token: workspace membership required for ${workspaceId}`);
381→    }
382→    const identityId = identityRecord.id as string;
383→
384→    const rawToken = generateProxyToken();
385→    const tokenHash = hashProxyToken(rawToken);
386→    const expiresAt = computeExpiresAt(proxyTokenTtlDays);
387→
388→    await wiringDeps.surreal.query(
389→      `BEGIN TRANSACTION;
390→       UPDATE proxy_token SET revoked = true WHERE identity = $identity AND workspace = $ws AND revoked = false;
391→       CREATE proxy_token CONTENT {
392→         token_hash: $hash,
393→         workspace: $ws,
394→         identity: $identity,
395→         expires_at: $expires,
396→         created_at: time::now(),
397→         revoked: false
398→       };
399→       COMMIT TRANSACTION;`,
400→      {
401→        hash: tokenHash,
402→        ws: workspaceRecord,
403→        identity: identityRecord,
404→        expires: expiresAt,
405→      },
406→    );
407→
408→    return { proxyToken: rawToken, identityId };
409→  };
410→
411→  const issueBrainMcpAuthEnv = async (
412→    workspaceId: string,
413→    identityId: string,
414→    intentGoal: string,
415→    intentReasoning: string,
416→  ): Promise<Record<string, string>> => {
417→    const dpopKeys = await generateKeyPair();
418→    const intentResult = await submitIntentForAuthorization(
419→      {
420→        workspace_id: workspaceId,
421→        identity_id: identityId,
422→        authorization_details: CLI_AUTHORIZATION_DETAILS,
423→        dpop_jwk_thumbprint: dpopKeys.thumbprint,
424→        goal: intentGoal,
425→        reasoning: intentReasoning,
426→      },
427→      {
428→        surreal: wiringDeps.surreal,
429→        extractionModel: wiringDeps.extractionModel,
430→      },
431→    );
432→
433→    let intentStatus: string = intentResult.status;
434→    if (intentStatus === "pending_auth") {
435→      const evaluation = await evaluatePendingIntent(
436→        intentResult.intentId,
437→        {
438→          surreal: wiringDeps.surreal,
439→          extractionModel: wiringDeps.extractionModel,
440→          llmEvaluator: async () => ({
441→            decision: "APPROVE",
442→            risk_score: 0,
443→            reason: "Approved from explicit authenticated orchestrator task assignment",
444→            reasoning:
445→              "User explicitly assigned this task in the orchestrator UI. " +
446→              "Bootstrap MCP token is required to complete the assigned task.",
447→          }),
448→        },
449→      );
450→      if (!evaluation.ok) {
451→        throw new Error(
452→          `Failed to evaluate MCP auth intent: ${evaluation.httpStatus} ${evaluation.error}`,
453→        );
454→      }
455→      intentStatus = evaluation.value.status;
456→    }
457→
458→    if (intentStatus !== "authorized") {
459→      throw new Error(`MCP auth intent is "${intentStatus}" (expected "authorized")`);
460→    }
461→
462→    const tokenResult = await exchangeIntentForToken({
463→      surreal: wiringDeps.surreal,
464→      asSigningKey: wiringDeps.asSigningKey,
465→      intentId: intentResult.intentId,
466→      authorizationDetails: CLI_AUTHORIZATION_DETAILS,
467→      proofThumbprint: dpopKeys.thumbprint,
468→    });
469→
470→    if (!tokenResult.ok) {
471→      throw new Error(
472→        `Failed to exchange MCP auth token: ${tokenResult.httpStatus} ${tokenResult.errorDescription}`,
473→      );
474→    }
475→
476→    const dpopTokenExpiresAt = Math.floor(Date.now() / 1000) + tokenResult.value.expiresIn;
477→
478→    return {
479→      BRAIN_CLIENT_ID: "orchestrator-session",
480→      BRAIN_ACCESS_TOKEN: "orchestrator-session",
481→      BRAIN_REFRESH_TOKEN: "orchestrator-session",
482→      BRAIN_TOKEN_EXPIRES_AT: String(dpopTokenExpiresAt),
483→      BRAIN_DPOP_PRIVATE_JWK: JSON.stringify(dpopKeys.privateJwk),
484→      BRAIN_DPOP_PUBLIC_JWK: JSON.stringify(dpopKeys.publicJwk),
485→      BRAIN_DPOP_THUMBPRINT: dpopKeys.thumbprint,
486→      BRAIN_DPOP_ACCESS_TOKEN: tokenResult.value.accessToken,
487→      BRAIN_DPOP_TOKEN_EXPIRES_AT: String(dpopTokenExpiresAt),
488→    };
489→  };
490→
491→  // Workspace access guard — resolves user from session cookie, checks membership
492→  const validateWorkspaceAccess = async (request: Request, workspaceId: string): Promise<Response | undefined> => {
493→    const session = await wiringDeps.auth.api.getSession({ headers: request.headers });
494→    if (!session?.user?.id) {
495→      return jsonError("authentication required", 401);
496→    }
497→    const { RecordId } = await import("surrealdb");
498→    const personRecord = new RecordId("person", session.user.id);
499→    const workspaceRecord = new RecordId("workspace", workspaceId);
500→    // member_of is identity->workspace; resolve person->identity via identity_person subquery
501→    const [memberRows] = await wiringDeps.surreal.query<[Array<{ role: string }>]>(
502→      `SELECT role FROM member_of WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person) AND out = $ws LIMIT 1;`,
503→      { person: personRecord, ws: workspaceRecord },
504→    );
505→    if (!memberRows || memberRows.length === 0) {
506→      return jsonError("not a member of this workspace", 403);
507→    }
508→    return undefined;
509→  };
510→
511→  // Lazy imports to keep module boundary clean
512→  const lifecycleImport = import("./session-lifecycle");
513→  const queriesImport = import("../mcp/mcp-queries");
514→  const guardImport = import("./assignment-guard");
515→  const stallDetectorImport = import("./stall-detector");
516→
517→  // Helper: resolve repo_path from workspace record
518→  const resolveRepoRoot = async (workspaceRecord: import("surrealdb").RecordId<"workspace", string>): Promise<string> => {
519→    const [rows] = await wiringDeps.surreal.query<[Array<{ repo_path?: string }>]>(
520→      `SELECT repo_path FROM $ws;`,
521→      { ws: workspaceRecord },
522→    );
523→    const repoPath = rows[0]?.repo_path;
524→    if (!repoPath) {
525→      throw new Error(`Workspace ${workspaceRecord.id} has no repo_path configured`);
526→    }
527→    return repoPath;
528→  };
529→
530→  const buildTaskScopedIntentContext = async (
531→    taskId: string,
532→  ): Promise<{ goal: string; reasoning: string }> => {
533→    const taskRecord = new RecordId("task", taskId);
534→    const [taskRows] = await wiringDeps.surreal.query<[Array<{ title?: string; description?: string }>]>(
535→      `SELECT title, description FROM $task LIMIT 1;`,
536→      { task: taskRecord },
537→    );
538→    const taskTitle = taskRows[0]?.title?.trim();
539→    const taskDescription = taskRows[0]?.description?.trim();
540→    const taskLabel = taskTitle && taskTitle.length > 0 ? taskTitle : taskId;
541→    const descriptionSuffix = taskDescription && taskDescription.length > 0
542→      ? ` Task description: ${taskDescription}`
543→      : "";
544→
545→    return {
546→      goal: `Complete task: ${taskLabel}`,
547→      reasoning: `Use Brain MCP tools required to complete task "${taskLabel}" in this workspace.${descriptionSuffix}`,
548→    };
549→  };
550→
551→  // Resolve adapter: real SDK adapter from deps > mock adapter > none (legacy spawn)
552→  const sandboxAdapterImport = wiringDeps.sandboxAgentAdapter
553→    ? Promise.resolve(wiringDeps.sandboxAgentAdapter)
554→    : wiringDeps.mockAgent
555→      ? import("./sandbox-adapter").then((mod) => mod.createMockAdapter())
556→      : undefined;
557→
558→  const spawnAgentImport = wiringDeps.mockAgent
559→    ? Promise.resolve({
560→        createSpawnAgent: (_qfn: import("./spawn-agent").QueryFn): import("./spawn-agent").SpawnAgentFn =>
561→          () => ({
562→            messages: (async function* () {})(),
563→            abort: () => {},
564→          }),
565→      })
566→    : import("./spawn-agent");
567→
568→  const routeDeps: OrchestratorRouteDeps = {
569→    createSession: async (workspaceId, taskId, authToken) => {
570→      const adapter = sandboxAdapterImport ? await sandboxAdapterImport : undefined;
571→      const [lifecycle, queries, guard, { createSpawnAgent }, stallDetector] = await Promise.all([
572→        lifecycleImport,
573→        queriesImport,
574→        guardImport,
575→        spawnAgentImport,
576→        stallDetectorImport,
577→      ]);
578→
579→      // When using adapter (sandbox path), skip proxy token / MCP auth setup
580→      // — the sandbox adapter manages its own auth. In mock mode, this avoids
581→      // requiring full OAuth infrastructure in acceptance tests.
582→      let proxyToken: string | undefined;
583→      let brainIdentityId: string | undefined;
584→      let brainAuthEnv: Record<string, string> = {};
585→
586→      if (!adapter) {
587→        try {
588→          const tokenResult = await issueProxyTokenForWorkspace(workspaceId, authToken);
589→          proxyToken = tokenResult.proxyToken;
590→          brainIdentityId = tokenResult.identityId;
591→          const intentContext = await buildTaskScopedIntentContext(taskId);
592→          brainAuthEnv = await issueBrainMcpAuthEnv(
593→            workspaceId,
594→            brainIdentityId,
595→            intentContext.goal,
596→            intentContext.reasoning,
597→          );
598→        } catch (err) {
599→          return {
600→            ok: false,
601→            error: {
602→              code: "SESSION_ERROR",
603→              message: err instanceof Error ? err.message : "Failed to issue proxy token",
604→              httpStatus: 500,
605→            },
606→          };
607→        }
608→      }
609→
610→      const spawnAgent = createSpawnAgent(wiringDeps.queryFn);
611→      const result = await lifecycle.createOrchestratorSession({
612→        surreal: wiringDeps.surreal,
613→        shellExec: wiringDeps.shellExec,
614→        brainBaseUrl: wiringDeps.brainBaseUrl,
615→        brainIdentityId,
616→        brainEnv: brainAuthEnv,
617→        anthropicBaseUrl: proxyToken ? `${wiringDeps.brainBaseUrl}/proxy/llm/anthropic` : undefined,
618→        anthropicCustomHeaders: proxyToken ? `X-Brain-Auth: ${proxyToken}` : undefined,
619→        workspaceId,
620→        taskId,
621→        authToken,
622→        validateAssignment: guard.validateAssignment,
623→        createAgentSession: queries.createAgentSession,
624→        spawnAgent,
625→        adapter,
626→        sandboxAgentType: wiringDeps.sandboxAgentType,
627→      });
628→
629→      // Wire SSE stream + event iteration on success
630→      if (result.ok && wiringDeps.sseRegistry) {
631→        const { agentSessionId, streamId, sessionHandle } = result.value;
632→        wiringDeps.sseRegistry.registerMessage(streamId);
633→
634→        // Adapter path: wire sandbox event bridge
635→        if (sessionHandle && adapter) {
636→          const { createSandboxEventBridge } = await import("./sandbox-event-bridge");
637→          const bridge = createSandboxEventBridge(
638→            {
639→              emitEvent: wiringDeps.sseRegistry.emitEvent,
640→              updateLastEventAt: async (sid) => {
641→                const rec = new RecordId("agent_session", sid);
642→                await wiringDeps.surreal.update(rec).merge({
643→                  last_event_at: new Date(),
644→                });
645→              },
646→              notifyStallDetector: () => {
647→                // Stall detector integration deferred to later step
648→              },
649→            },
650→            streamId,
651→            agentSessionId,
652→          );
653→          sessionHandle.onEvent((event) => {
654→            bridge.handleEvent(event as import("./sandbox-event-bridge").SandboxEvent);
655→          });
656→        } else {
657→          // Legacy path: SDK message stream iteration
658→          const handle = lifecycle.getHandle(agentSessionId);
659→          if (handle) {
660→            const { RecordId } = await import("surrealdb");
661→            lifecycle.startEventIteration(
662→              {
663→                emitEvent: wiringDeps.sseRegistry.emitEvent,
664→                updateSessionStatus: async (sid, status, error) => {
665→                  const rec = new RecordId("agent_session", sid);
666→                  await wiringDeps.surreal.update(rec).merge({
667→                    orchestrator_status: status,
668→                    ...(error !== undefined ? { error_message: error } : {}),
669→                  });
670→                },
671→                updateLastEventAt: async (sid) => {
672→                  const rec = new RecordId("agent_session", sid);
673→                  await wiringDeps.surreal.update(rec).merge({
674→                    last_event_at: new Date(),
675→                  });
676→                },
677→                getSessionStatus: async (sid) => {
678→                  const rec = new RecordId("agent_session", sid);
679→                  const row = await wiringDeps.surreal.select(rec) as { orchestrator_status?: string } | undefined;
680→                  return (row?.orchestrator_status ?? "error") as import("./types").OrchestratorStatus;
681→                },
682→                startStallDetector: (sid, stId) =>
683→                  stallDetector.startStallDetector(
684→                    {
685→                      abortSession: async (abortSid) => {
686→                        const abortResult = await lifecycle.abortOrchestratorSession({
687→                          surreal: wiringDeps.surreal,
688→                          shellExec: wiringDeps.shellExec,
689→                          resolveRepoRoot,
690→                          sessionId: abortSid,
691→                          endAgentSession: queries.endAgentSession,
692→                        });
693→                        return abortResult;
694→                      },
695→                      createObservation: async () => {},
696→                      emitEvent: wiringDeps.sseRegistry!.emitEvent,
697→                    },
698→                    stallDetector.DEFAULT_STALL_CONFIG,
699→                    sid,
700→                    stId,
701→                  ),
702→              },
703→              handle.messages,
704→              streamId,
705→              agentSessionId,
706→            );
707→          }
708→        }
709→      }
710→
711→      return result;
712→    },
713→
714→    getSessionStatus: async (sessionId) => {
715→      const lifecycle = await lifecycleImport;
716→      return lifecycle.getOrchestratorSessionStatus({
717→        surreal: wiringDeps.surreal,
718→        sessionId,
719→      });
720→    },
721→
722→    abortSession: async (sessionId) => {
723→      const adapter = sandboxAdapterImport ? await sandboxAdapterImport : undefined;
724→      const [lifecycle, queries] = await Promise.all([
725→        lifecycleImport,
726→        queriesImport,
727→      ]);
728→      return lifecycle.abortOrchestratorSession({
729→        surreal: wiringDeps.surreal,
730→        shellExec: wiringDeps.shellExec,
731→        resolveRepoRoot,
732→        sessionId,
733→        adapter,
734→        endAgentSession: queries.endAgentSession,
735→      });
736→    },
737→
738→    acceptSession: async (sessionId, summary) => {
739→      const [lifecycle, queries] = await Promise.all([
740→        lifecycleImport,
741→        queriesImport,
742→      ]);
743→      return lifecycle.acceptOrchestratorSession({
744→        surreal: wiringDeps.surreal,
745→        sessionId,
746→        summary,
747→        endAgentSession: queries.endAgentSession,
748→      });
749→    },
750→
751→    getReview: async (sessionId) => {
752→      const [lifecycle, worktreeManager] = await Promise.all([
753→        lifecycleImport,
754→        import("./worktree-manager"),
755→      ]);
756→      return lifecycle.getOrchestratorReview({
757→        surreal: wiringDeps.surreal,
758→        sessionId,
759→        resolveRepoRoot,
760→        getDiff: (repoRoot: string, branchName: string) =>
761→          worktreeManager.getDiff(wiringDeps.shellExec, repoRoot, branchName),
762→        getTaskTitle: async (taskId: string) => {
763→          const { RecordId } = await import("surrealdb");
764→          const taskRecord = new RecordId("task", taskId);
765→          const rows = (await wiringDeps.surreal.query(
766→            `SELECT title FROM $task;`,
767→            { task: taskRecord },
768→          )) as Array<Array<{ title: string }>>;
769→          return rows[0]?.[0]?.title ?? "";
770→        },
771→      });
772→    },
773→
774→    rejectSession: async (sessionId, feedback) => {
775→      const lifecycle = await lifecycleImport;
776→      return lifecycle.rejectOrchestratorSession({
777→        surreal: wiringDeps.surreal,
778→        sessionId,
779→        feedback,
780→      });
781→    },
782→
783→    sendPrompt: async (sessionId, text) => {
784→      const adapter = sandboxAdapterImport ? await sandboxAdapterImport : undefined;
785→      const lifecycle = await lifecycleImport;
786→      return lifecycle.sendSessionPrompt({
787→        surreal: wiringDeps.surreal,
788→        sessionId,
789→        text,
790→        adapter,
791→      });
792→    },
793→  };
794→
795→  const handlers = createOrchestratorRouteHandlers(routeDeps);
796→
797→  // Wrap handler with workspace access check
798→  const withWorkspaceAccess = (handler: RouteHandler): RouteHandler => async (request) => {
799→    const workspaceId = request.params.workspaceId;
800→    if (workspaceId) {
801→      const accessError = await validateWorkspaceAccess(request, workspaceId);
802→      if (accessError) return accessError;
803→    }
804→    return handler(request);
805→  };
806→
807→  const streamHandler = wiringDeps.sseRegistry
808→    ? createStreamRouteHandler({ sseRegistry: wiringDeps.sseRegistry })
809→    : undefined;
810→
811→  return {
812→    assign: withTracing("orchestrator.assign", "POST", withWorkspaceAccess(handlers.assign)),
813→    status: withTracing("orchestrator.status", "GET", withWorkspaceAccess(handlers.status)),
814→    accept: withTracing("orchestrator.accept", "POST", withWorkspaceAccess(handlers.accept)),
815→    abort: withTracing("orchestrator.abort", "POST", withWorkspaceAccess(handlers.abort)),
816→    review: withTracing("orchestrator.review", "GET", withWorkspaceAccess(handlers.review)),
817→    reject: withTracing("orchestrator.reject", "POST", withWorkspaceAccess(handlers.reject)),
818→    prompt: withTracing("orchestrator.prompt", "POST", withWorkspaceAccess(handlers.prompt)),
819→    ...(streamHandler
820→      ? { stream: withTracing("orchestrator.stream", "GET", withWorkspaceAccess(streamHandler.stream)) }
821→      : {}),
822→  };
823→}
