 64→/**
 65→ * Split SQL into statements respecting `{...}` block nesting.
 66→ * DEFINE FUNCTION / DEFINE EVENT bodies contain semicolons that are NOT
 67→ * statement terminators. Naively splitting on `;` breaks those bodies into
 68→ * orphaned fragments that corrupt the batch query.
 69→ */
 70→function splitSqlStatements(sql: string): string[] {
 71→  const stmts: string[] = [];
 72→  let current = "";
 73→  let depth = 0;
 74→  for (let i = 0; i < sql.length; i++) {
 75→    const ch = sql[i];
 76→    if (ch === "{") depth++;
 77→    else if (ch === "}") depth--;
 78→
 79→    if (ch === ";" && depth === 0) {
 80→      const trimmed = current.trim();
 81→      if (trimmed.length > 0) stmts.push(trimmed);
 82→      current = "";
 83→    } else {
 84→      current += ch;
 85→    }
 86→  }
 87→  const trimmed = current.trim();
 88→  if (trimmed.length > 0) stmts.push(trimmed);
 89→  return stmts;
 90→}
