440→function base64url(buf: Buffer): string {
441→  return buf.toString("base64url");
442→}
443→
444→function generatePkce(): { verifier: string; challenge: string } {
445→  const verifier = base64url(randomBytes(32));
446→  const challenge = base64url(createHash("sha256").update(verifier).digest());
447→  return { verifier, challenge };
448→}
