218→function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
219→  const result: Record<string, unknown> = {};
220→  for (const [key, value] of Object.entries(obj)) {
221→    if (value !== undefined) {
222→      result[key] = value;
223→    }
224→  }
225→  return result as Partial<T>;
226→}
