742→
743→type AcceptSessionInput = {
744→  surreal: Surreal;
745→  sessionId: string;
746→  summary: string;
747→  endAgentSession: (input: {
748→    surreal: Surreal;
749→    workspaceRecord: RecordId<"workspace", string>;
750→    sessionId: string;
751→    summary: string;
752→  }) => Promise<{ session_id: string; ended: boolean }>;
