754→
755→export async function acceptOrchestratorSession(
756→  input: AcceptSessionInput,
757→): Promise<AcceptSessionResult> {
758→  const lookup = await lookupSession(input.surreal, input.sessionId);
759→  if (!lookup.ok) {
760→    return { ok: false, error: lookup.error };
761→  }
762→  const { session, record: sessionRecord, status } = lookup;
763→
764→  if (!ACCEPTABLE_STATUSES.has(status)) {
765→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
766→  }
767→
768→  const workspaceRecord = requireWorkspace(session, input.sessionId);
769→
770→  // 1. Update orchestrator_status to completed
771→  await input.surreal.update(sessionRecord).merge({
772→    orchestrator_status: "completed" as OrchestratorStatus,
773→  });
774→
775→  // 2. (handle registry eliminated — no cleanup needed)
776→
777→  // 3. End the agent session
778→  await input.endAgentSession({
779→    surreal: input.surreal,
780→    workspaceRecord,
781→    sessionId: input.sessionId,
782→    summary: input.summary,
783→  });
784→
785→  return {
786→    ok: true,
787→    value: {
788→      accepted: true,
789→      sessionId: input.sessionId,
790→    },
791→  };
792→}
793→
794→// ---------------------------------------------------------------------------
795→// State guard helpers
796→// ---------------------------------------------------------------------------
797→
798→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
799→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
800→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
801→const PROMPTABLE_STATUSES = new Set<OrchestratorStatus>(["spawning", "active", "idle"]);
802→
803→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
804→  return {
805→    code: "SESSION_ERROR",
806→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
807→    httpStatus: 409,
808→  };
809→}
810→
811→function sessionAborted(sessionId: string): SessionError {
812→  return {
813→    code: "SESSION_ERROR",
814→    message: `Session ${sessionId} has been aborted`,
815→    httpStatus: 409,
816→  };
817→}
818→
819→// ---------------------------------------------------------------------------
820→// getOrchestratorReview
821→// ---------------------------------------------------------------------------
822→
823→type GetReviewInput = {
824→  surreal: Surreal;
825→  sessionId: string;
826→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
827→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
828→  getTaskTitle: (taskId: string) => Promise<string>;
829→};
830→
831→export async function getOrchestratorReview(
832→  input: GetReviewInput,
833→): Promise<ReviewResult> {
834→  const lookup = await lookupSession(input.surreal, input.sessionId);
835→  if (!lookup.ok) {
836→    return { ok: false, error: lookup.error };
837→  }
838→  const { session, status } = lookup;
839→
840→  if (status === "aborted") {
841→    return { ok: false, error: sessionAborted(input.sessionId) };
842→  }
843→
844→  if (!REVIEWABLE_STATUSES.has(status)) {
845→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
846→  }
847→
848→  // Get diff from the branch
849→  const branchName = session.worktree_branch ?? "";
850→  const workspaceRecord = requireWorkspace(session, input.sessionId);
851→  const repoRoot = await input.resolveRepoRoot(workspaceRecord);
852→  const diffResult = await input.getDiff(repoRoot, branchName);
853→
854→  const diff = diffResult.ok
855→    ? diffResult.value
856→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
857→
858→  // Get task title
859→  const taskId = session.task_id ? session.task_id.id : "";
860→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
861→
862→  return {
863→    ok: true,
864→    value: {
865→      taskTitle,
866→      diff,
867→      session: {
868→        orchestratorStatus: status,
869→        ...pickDefined({
870→          worktreeBranch: session.worktree_branch,
871→          startedAt: session.started_at,
872→          lastEventAt: session.last_event_at,
873→        }),
874→      },
875→    },
876→  };
877→}
878→
879→// ---------------------------------------------------------------------------
880→// rejectOrchestratorSession
881→// ---------------------------------------------------------------------------
882→
883→type RejectSessionInput = {
884→  surreal: Surreal;
885→  sessionId: string;
886→  feedback: string;
887→};
888→
889→export async function rejectOrchestratorSession(
890→  input: RejectSessionInput,
891→): Promise<RejectSessionResult> {
892→  const lookup = await lookupSession(input.surreal, input.sessionId);
893→  if (!lookup.ok) {
894→    return { ok: false, error: lookup.error };
895→  }
896→  const { session, record: sessionRecord, status } = lookup;
897→
898→  if (!REJECTABLE_STATUSES.has(status)) {
899→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
900→  }
901→
902→  // 1. Update session status to active (agent resumes work)
903→  await input.surreal.update(sessionRecord).merge({
904→    orchestrator_status: "active" as OrchestratorStatus,
905→    last_feedback: input.feedback,
906→  });
907→
908→  // 2. Return task to in_progress
909→  if (session.task_id) {
910→    await input.surreal.update(session.task_id).merge({
911→      status: "in_progress",
912→      updated_at: new Date(),
913→    });
914→  }
915→
916→  return {
917→    ok: true,
918→    value: {
919→      rejected: true,
920→      continuing: true,
921→    },
922→  };
923→}
924→
925→// ---------------------------------------------------------------------------
926→// sendSessionPrompt
927→// ---------------------------------------------------------------------------
928→
929→type SendPromptInput = {
930→  surreal: Surreal;
931→  sessionId: string;
932→  text: string;
933→  adapter?: SandboxAgentAdapter;
934→};
935→
936→export async function sendSessionPrompt(
937→  input: SendPromptInput,
938→): Promise<PromptSessionResult> {
939→  const lookup = await lookupSession(input.surreal, input.sessionId);
940→  if (!lookup.ok) {
941→    return { ok: false, error: lookup.error };
942→  }
943→  const { session, status } = lookup;
944→
945→  if (!PROMPTABLE_STATUSES.has(status)) {
946→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "prompt") };
947→  }
948→
949→  // ── Adapter path: delegate to SandboxAgentAdapter ──
950→  if (input.adapter && session.external_session_id) {
951→    try {
952→      const handle = await input.adapter.resumeSession(session.external_session_id);
953→      await handle.prompt([{ type: "text", text: input.text }]);
954→      return { ok: true, value: { delivered: true } };
955→    } catch (err) {
956→      return {
957→        ok: false,
958→        error: {
959→          code: "SESSION_ERROR",
960→          message: `Failed to deliver prompt: ${err instanceof Error ? err.message : String(err)}`,
961→          httpStatus: 500,
962→        },
963→      };
964→    }
965→  }
966→
967→  // ── Legacy path: Agent SDK does not support follow-up prompts ──
968→  return {
969→    ok: false,
970→    error: {
971→      code: "SESSION_ERROR",
972→      message: `Follow-up prompts are not supported with the Agent SDK. Session ${input.sessionId} runs a single query() conversation.`,
973→      httpStatus: 409,
974→    },
975→  };
976→}
