 92→// ---------------------------------------------------------------------------
 93→// Request body parsing
 94→// ---------------------------------------------------------------------------
 95→
 96→type AssignBody = { taskId?: string };
 97→type AcceptBody = { summary?: string };
 98→type RejectBody = { feedback?: string };
 99→type PromptBody = { text?: string };
100→
101→async function parseJsonBody<T>(request: Request): Promise<T | undefined> {
102→  try {
103→    return (await request.json()) as T;
104→  } catch {
105→    return undefined;
106→  }
107→}
108→
109→function extractAuthToken(request: Request): string {
110→  return request.headers.get("Cookie") ?? "";
111→}
112→
113→// ---------------------------------------------------------------------------
114→// Response builders (pure)
115→// ---------------------------------------------------------------------------
116→
117→function assignResponse(
118→  workspaceId: string,
119→  value: { agentSessionId: string; streamId: string; worktreeBranch: string },
120→): Response {
121→  return jsonResponse(
122→    {
123→      agentSessionId: value.agentSessionId,
124→      streamId: value.streamId,
125→      streamUrl: `/api/orchestrator/${workspaceId}/sessions/${value.agentSessionId}/stream`,
126→    },
127→    200,
128→  );
129→}
130→
131→function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
132→  const result: Record<string, unknown> = {};
133→  for (const [key, value] of Object.entries(obj)) {
134→    if (value !== undefined) {
135→      result[key] = value;
136→    }
137→  }
138→  return result as Partial<T>;
139→}
140→
141→function statusResponse(
142→  sessionId: string,
143→  value: {
144→    orchestratorStatus: string;
145→    worktreeBranch?: string;
146→    worktreePath?: string;
147→    startedAt?: string;
148→    lastEventAt?: string;
149→    error?: string;
150→  },
151→): Response {
152→  return jsonResponse(
153→    {
154→      agentSessionId: sessionId,
155→      orchestratorStatus: value.orchestratorStatus,
156→      ...pickDefined({
157→        worktreeBranch: value.worktreeBranch,
158→        worktreePath: value.worktreePath,
159→        startedAt: value.startedAt,
160→        lastEventAt: value.lastEventAt,
161→        error: value.error,
162→      }),
163→    },
164→    200,
165→  );
166→}
167→
168→function acceptResponse(): Response {
169→  return jsonResponse({ accepted: true, taskStatus: "done" }, 200);
170→}
171→
172→function abortResponse(): Response {
173→  return jsonResponse({ aborted: true, taskStatus: "ready" }, 200);
174→}
175→
176→function reviewResponse(value: {
177→  taskTitle: string;
178→  diff: unknown;
179→  session: unknown;
180→}): Response {
181→  return jsonResponse(value, 200);
182→}
183→
184→function rejectResponse(): Response {
185→  return jsonResponse({ rejected: true, continuing: true }, 200);
186→}
187→
188→function promptResponse(): Response {
189→  return jsonResponse({ delivered: true }, 202);
190→}
191→
192→function sessionErrorResponse(error: {
193→  message: string;
194→  httpStatus: number;
195→}): Response {
196→  return jsonError(error.message, error.httpStatus);
197→}
