199→// ---------------------------------------------------------------------------
200→// Route handler factory
201→// ---------------------------------------------------------------------------
202→
203→export function createOrchestratorRouteHandlers(deps: OrchestratorRouteDeps) {
204→  const assign: RouteHandler = async (request) => {
205→    const workspaceId = request.params.workspaceId;
206→    const body = await parseJsonBody<AssignBody>(request);
207→
208→    if (!body?.taskId) {
209→      return jsonError("taskId is required", 400);
210→    }
211→
212→    const authToken = extractAuthToken(request);
213→    const result = await deps.createSession(workspaceId, body.taskId, authToken);
214→
215→    if (!result.ok) {
216→      return sessionErrorResponse(result.error);
217→    }
218→
219→    return assignResponse(workspaceId, result.value);
220→  };
221→
222→  const status: RouteHandler = async (request) => {
223→    const sessionId = request.params.sessionId;
224→    const result = await deps.getSessionStatus(sessionId);
225→
226→    if (!result.ok) {
227→      return sessionErrorResponse(result.error);
228→    }
229→
230→    return statusResponse(sessionId, result.value);
231→  };
232→
233→  const accept: RouteHandler = async (request) => {
234→    const sessionId = request.params.sessionId;
235→    const body = await parseJsonBody<AcceptBody>(request);
236→    const summary = body?.summary ?? "";
237→
238→    const result = await deps.acceptSession(sessionId, summary);
239→
240→    if (!result.ok) {
241→      return sessionErrorResponse(result.error);
242→    }
243→
244→    return acceptResponse();
245→  };
246→
247→  const abort: RouteHandler = async (request) => {
248→    const sessionId = request.params.sessionId;
249→    const result = await deps.abortSession(sessionId);
250→
251→    if (!result.ok) {
252→      return sessionErrorResponse(result.error);
253→    }
254→
255→    return abortResponse();
256→  };
257→
258→  const review: RouteHandler = async (request) => {
259→    const sessionId = request.params.sessionId;
260→    const result = await deps.getReview(sessionId);
261→
262→    if (!result.ok) {
263→      return sessionErrorResponse(result.error);
264→    }
265→
266→    return reviewResponse(result.value);
267→  };
268→
269→  const reject: RouteHandler = async (request) => {
270→    const sessionId = request.params.sessionId;
271→    const body = await parseJsonBody<RejectBody>(request);
272→
273→    if (!body?.feedback || body.feedback.trim() === "") {
274→      return jsonError("feedback is required", 400);
275→    }
276→
277→    const result = await deps.rejectSession(sessionId, body.feedback);
278→
279→    if (!result.ok) {
280→      return sessionErrorResponse(result.error);
281→    }
282→
283→    return rejectResponse();
284→  };
285→
286→  const prompt: RouteHandler = async (request) => {
287→    const sessionId = request.params.sessionId;
288→    const body = await parseJsonBody<PromptBody>(request);
289→
290→    if (!body?.text || body.text.trim() === "") {
291→      return jsonError("text is required", 400);
292→    }
293→
294→    const result = await deps.sendPrompt(sessionId, body.text);
295→
296→    if (!result.ok) {
297→      return sessionErrorResponse(result.error);
298→    }
299→
300→    return promptResponse();
301→  };
302→
303→  return { assign, status, accept, abort, review, reject, prompt };
304→}
