 90→        repoPath,
 91→      },
 92→    }),
 93→  };
 94→}
 95→
 96→function createAgentSessionStub(returnSessionId = "agent-sess-1") {
 97→  return {
 98→    fn: async (_input: Record<string, unknown>) => ({
 99→      session_id: returnSessionId,
100→    }),
101→  };
102→}
103→
104→// ---------------------------------------------------------------------------
105→// Helper: create a session to populate the handle registry
106→// ---------------------------------------------------------------------------
107→
108→async function seedSessionWithHandle(
109→  surrealSpy: SurrealSpy,
110→  agentSessionId: string,
111→) {
112→  const { spawn } = spawnAgentStub();
113→  const agentSessionStub = createAgentSessionStub(agentSessionId);
114→  const assignmentStub = validateAssignmentStubOk();
115→
116→  await createOrchestratorSession({
