128→// ---------------------------------------------------------------------------
129→// Tests: sendSessionPrompt
130→// ---------------------------------------------------------------------------
131→
132→describe("sendSessionPrompt", () => {
133→  beforeEach(() => {
134→    clearHandleRegistry();
135→  });
136→
137→  test("returns not-supported error for active session (SDK has no sendPrompt)", async () => {
138→    const surrealSpy = createSurrealSpy({
139→      sessionSelect: {
140→        id: new RecordId("agent_session", "sess-1"),
141→        orchestrator_status: "active",
142→        workspace: new RecordId("workspace", "ws-1"),
143→      },
144→    });
145→
