255→
256→type SessionRow = {
257→  id: RecordId<"agent_session", string>;
258→  orchestrator_status?: string;
259→  worktree_branch?: string;
260→  worktree_path?: string;
261→  started_at?: string;
262→  last_event_at?: string;
263→  task_id?: RecordId<"task", string>;
264→  workspace?: RecordId<"workspace", string>;
265→  error_message?: string;
266→  external_session_id?: string;
267→  session_type?: string;
