269→
270→type SessionLookup =
271→  | { ok: true; session: SessionRow; record: RecordId<"agent_session", string>; status: OrchestratorStatus }
272→  | { ok: false; error: SessionError };
273→
274→async function lookupSession(
275→  surreal: Surreal,
276→  sessionId: string,
277→): Promise<SessionLookup> {
278→  const record = new RecordId("agent_session", sessionId);
279→  const session = await surreal.select<SessionRow>(record);
280→  if (!session) {
281→    return { ok: false, error: sessionNotFound(sessionId) };
282→  }
283→  if (!session.orchestrator_status) {
284→    throw new Error(`agent_session ${sessionId} missing orchestrator_status — data corruption`);
285→  }
286→  const status = session.orchestrator_status as OrchestratorStatus;
287→  return { ok: true, session, record, status };
288→}
289→
290→function requireWorkspace(session: SessionRow, sessionId: string): RecordId<"workspace", string> {
291→  if (!session.workspace) {
292→    throw new Error(`agent_session ${sessionId} missing workspace — data corruption`);
293→  }
294→  return session.workspace as RecordId<"workspace", string>;
295→}
296→
297→function generateStreamId(sessionId: string): string {
298→  return `stream-${sessionId}`;
299→}
300→
301→function appendOrchestratorProxyHeaders(
302→  baseHeaders: string,
303→  taskId: string,
304→  sessionId: string,
305→): string {
306→  const lines = baseHeaders
307→    .split(/\r?\n/)
308→    .map((line) => line.trim())
309→    .filter((line) => line.length > 0);
310→
311→  const headerMap = new Map<string, string>();
312→  for (const line of lines) {
313→    const sep = line.indexOf(":");
314→    if (sep <= 0) {
315→      continue;
316→    }
317→    const name = line.slice(0, sep).trim();
318→    const value = line.slice(sep + 1).trim();
319→    if (name.length === 0 || value.length === 0) {
320→      continue;
321→    }
322→    headerMap.set(name.toLowerCase(), `${name}: ${value}`);
323→  }
324→
325→  headerMap.set("x-brain-task", `X-Brain-Task: ${taskId}`);
326→  headerMap.set("x-brain-session", `X-Brain-Session: ${sessionId}`);
327→
328→  return Array.from(headerMap.values()).join("\n");
329→}
330→
331→function slugFromTitle(title: string): string {
332→  return title
333→    .toLowerCase()
334→    .replace(/[^a-z0-9]+/g, "-")
335→    .replace(/^-|-$/g, "")
336→    .slice(0, 50);
337→}
