487→// ---------------------------------------------------------------------------
488→// Intent authorization helpers
489→// ---------------------------------------------------------------------------
490→
491→async function checkIntentAuthorization(
492→  surreal: Surreal,
493→  intentId: string,
494→  workspaceId: string,
495→): Promise<SessionResult<void>> {
496→  const intent = await getIntentById(surreal, intentId);
497→  if (!intent) {
498→    return {
499→      ok: false,
500→      error: {
501→        code: "INTENT_NOT_AUTHORIZED",
502→        message: `Intent ${intentId} not found`,
503→        httpStatus: 404,
504→      },
505→    };
506→  }
507→
508→  // Validate workspace scope: intent must belong to the session's workspace
509→  const intentWorkspaceId = intent.workspace.id as string;
510→  if (intentWorkspaceId !== workspaceId) {
511→    return {
512→      ok: false,
513→      error: {
514→        code: "WORKSPACE_MISMATCH",
515→        message: `Intent ${intentId} belongs to workspace "${intentWorkspaceId}", not "${workspaceId}"`,
516→        httpStatus: 403,
517→      },
518→    };
519→  }
520→
521→  const status = intent.status as IntentStatus;
522→  if (status !== "authorized") {
523→    return {
524→      ok: false,
525→      error: {
526→        code: "INTENT_NOT_AUTHORIZED",
527→        message: `Intent ${intentId} has status "${status}", expected "authorized"`,
528→        httpStatus: 403,
529→      },
530→    };
531→  }
532→
533→  return { ok: true, value: undefined as void };
534→}
535→
536→async function transitionIntentToExecuting(
537→  surreal: Surreal,
538→  intentId: string,
539→  sessionRecord: RecordId<"agent_session", string>,
540→): Promise<void> {
541→  await updateIntentStatus(surreal, intentId, "executing");
542→
543→  const intentRecord = new RecordId("intent", intentId);
544→  // NOTE: `$session` is a SurrealDB protected variable — use `$sess` instead
545→  await surreal.query(
546→    "RELATE $intent->gates->$sess SET created_at = time::now();",
547→    { intent: intentRecord, sess: sessionRecord },
548→  );
549→
550→  log.info("orchestrator.intent-gate", "Intent transitioned to executing with gates relation", {
551→    intentId,
552→    sessionId: sessionRecord.id as string,
553→  });
554→}
