559→
560→async function createSessionViaAdapter(
561→  input: CreateSessionInput,
562→  validation: import("./types").AssignmentValidation,
563→): Promise<OrchestratorSessionResult> {
564→  const adapter = input.adapter!;
565→
566→  // 1. Create agent_session record
567→  const { session_id: agentSessionId } = await input.createAgentSession({
568→    surreal: input.surreal,
569→    agent: "claude",
570→    workspaceRecord: validation.workspaceRecord,
571→    taskId: input.taskId,
572→  });
573→
574→  const streamId = generateStreamId(agentSessionId);
575→
576→  // 2. Create session via adapter
577→  let handle: SessionHandle;
578→  try {
579→    handle = await adapter.createSession({
580→      agent: input.sandboxAgentType ?? "claude",
581→      cwd: validation.repoPath,
582→    });
583→  } catch (err) {
584→    // Rollback: delete agent_session on adapter failure
585→    const sessionRecord = new RecordId("agent_session", agentSessionId);
586→    await input.surreal.delete(sessionRecord);
587→    return {
588→      ok: false,
589→      error: worktreeError(`Failed to create sandbox session: ${err instanceof Error ? err.message : String(err)}`),
590→    };
591→  }
592→
593→  // 3. Update agent_session with sandbox fields
594→  const sessionRecord = new RecordId("agent_session", agentSessionId);
595→  await input.surreal.update(sessionRecord).merge({
596→    orchestrator_status: "spawning" as OrchestratorStatus,
597→    stream_id: streamId,
598→    session_type: "sandbox_agent",
599→    provider: "local",
600→    external_session_id: handle.id,
601→  });
602→
603→  // 4. Transition intent to executing
604→  if (input.intentId) {
605→    await transitionIntentToExecuting(input.surreal, input.intentId, sessionRecord);
606→  }
607→
608→  return {
609→    ok: true,
610→    value: {
611→      agentSessionId,
612→      streamId,
613→      worktreeBranch: `sandbox-${agentSessionId}`,
614→      sessionHandle: handle,
615→    },
616→  };
617→}
