  1→/**
  2→ * SurrealDB CRUD operations for sandbox agent sessions.
  3→ *
  4→ * Pure query builders — each function accepts a Surreal instance
  5→ * as its first parameter (dependency injection, no module-level singleton).
  6→ *
  7→ * Replaces the in-memory handleRegistry for sandbox session state.
  8→ */
  9→import { RecordId, type Surreal } from "surrealdb";
 10→
 11→// ---------------------------------------------------------------------------
 12→// Types
 13→// ---------------------------------------------------------------------------
 14→
 15→export type CreateSandboxSessionInput = {
 16→  surreal: Surreal;
 17→  workspaceId: string;
 18→  agent: string;
 19→  provider: string;
 20→  taskId?: string;
 21→};
 22→
 23→export type CreateSandboxSessionResult = {
 24→  sessionId: string;
 25→  streamId: string;
 26→};
 27→
 28→export type SandboxSessionRecord = {
 29→  id: RecordId<"agent_session", string>;
 30→  workspace: RecordId<"workspace", string>;
 31→  session_type: string;
 32→  provider?: string;
 33→  orchestrator_status: string;
 34→  external_session_id?: string;
 35→  agent: string;
 36→  created_at: string;
 37→  started_at: string;
 38→  ended_at?: string;
 39→  last_event_at?: string;
 40→};
 41→
 42→// ---------------------------------------------------------------------------
 43→// createSandboxSession
 44→// ---------------------------------------------------------------------------
 45→
 46→export async function createSandboxSession(
 47→  input: CreateSandboxSessionInput,
 48→): Promise<CreateSandboxSessionResult> {
 49→  const sessionId = crypto.randomUUID();
 50→  const streamId = `stream-${sessionId}`;
 51→  const record = new RecordId("agent_session", sessionId);
 52→  const workspace = new RecordId("workspace", input.workspaceId);
 53→
 54→  const vars: Record<string, unknown> = {
 55→    record,
 56→    agent: input.agent,
 57→    workspace,
 58→    session_type: "sandbox_agent",
 59→    provider: input.provider,
 60→    orchestrator_status: "running",
 61→    stream_id: streamId,
 62→    started_at: new Date().toISOString(),
 63→    created_at: new Date().toISOString(),
 64→  };
 65→
 66→  if (input.taskId) {
 67→    vars.task_id = new RecordId("task", input.taskId);
 68→  }
 69→
 70→  await input.surreal.query(
 71→    `CREATE $record CONTENT {
 72→      agent: $agent,
 73→      workspace: $workspace,
 74→      session_type: $session_type,
 75→      provider: $provider,
 76→      orchestrator_status: $orchestrator_status,
 77→      stream_id: $stream_id,
 78→      started_at: $started_at,
 79→      created_at: $created_at
 80→    };`,
 81→    vars,
 82→  );
 83→
 84→  return { sessionId, streamId };
 85→}
 86→
 87→// ---------------------------------------------------------------------------
 88→// updateSessionStatus
 89→// ---------------------------------------------------------------------------
 90→
 91→export async function updateSessionStatus(
 92→  surreal: Surreal,
 93→  sessionId: string,
 94→  status: string,
 95→  errorMessage?: string,
 96→): Promise<void> {
 97→  const record = new RecordId("agent_session", sessionId);
 98→
 99→  const vars: Record<string, unknown> = {
100→    record,
101→    status,
102→  };
103→
104→  const setClause = errorMessage
105→    ? "orchestrator_status = $status, error_message = $error_message, ended_at = time::now()"
106→    : status === "completed" || status === "aborted" || status === "error"
107→      ? "orchestrator_status = $status, ended_at = time::now()"
108→      : "orchestrator_status = $status";
109→
110→  if (errorMessage) {
111→    vars.error_message = errorMessage;
112→  }
113→
114→  await surreal.query(
115→    `UPDATE $record SET ${setClause};`,
116→    vars,
117→  );
118→}
