121→// getActiveSandboxSessions
122→// ---------------------------------------------------------------------------
123→
124→export async function getActiveSandboxSessions(
125→  surreal: Surreal,
126→  workspaceId: string,
127→): Promise<SandboxSessionRecord[]> {
128→  const workspace = new RecordId("workspace", workspaceId);
129→
130→  const result = await surreal.query<[SandboxSessionRecord[]]>(
131→    `SELECT * FROM agent_session
132→     WHERE workspace = $workspace
133→       AND session_type = $session_type
134→       AND orchestrator_status IN $active_statuses
135→     ORDER BY created_at DESC;`,
136→    {
137→      workspace,
138→      session_type: "sandbox_agent",
139→      active_statuses: ["running", "idle", "restoring"],
140→    },
141→  );
142→
143→  return result[0] ?? [];
144→}
