 49→
 50→export function loadServerConfig(): ServerConfig {
 51→  const inferenceProvider = parseInferenceProvider();
 52→
 53→  const openRouterApiKey = inferenceProvider === "openrouter"
 54→    ? requireEnv("OPENROUTER_API_KEY")
 55→    : Bun.env.OPENROUTER_API_KEY?.trim() || undefined;
 56→
 57→  const ollamaBaseUrl = inferenceProvider === "ollama"
 58→    ? (Bun.env.OLLAMA_BASE_URL?.trim() || "http://127.0.0.1:11434")
 59→    : undefined;
 60→
 61→  const extractionStoreThreshold = parseUnitInterval(
 62→    requireEnv("EXTRACTION_STORE_THRESHOLD"),
 63→    "EXTRACTION_STORE_THRESHOLD",
 64→  );
 65→
 66→  const extractionDisplayThreshold = parseUnitInterval(
 67→    requireEnv("EXTRACTION_DISPLAY_THRESHOLD"),
 68→    "EXTRACTION_DISPLAY_THRESHOLD",
 69→  );
 70→
 71→  if (extractionDisplayThreshold < extractionStoreThreshold) {
 72→    throw new Error("EXTRACTION_DISPLAY_THRESHOLD must be greater than or equal to EXTRACTION_STORE_THRESHOLD");
 73→  }
 74→
 75→  const chatAgentModelId = requireEnv("CHAT_AGENT_MODEL");
 76→  const extractionModelId = requireEnv("EXTRACTION_MODEL");
 77→  const pmAgentModelId = optionalEnv("PM_AGENT_MODEL") ?? extractionModelId;
 78→  const analyticsAgentModelId = requireEnv("ANALYTICS_MODEL");
 79→  const surrealUrl = requireEnv("SURREAL_URL");
 80→  const surrealUsername = requireEnv("SURREAL_USERNAME");
 81→  const surrealPassword = requireEnv("SURREAL_PASSWORD");
 82→  const surrealNamespace = requireEnv("SURREAL_NAMESPACE");
 83→  const surrealDatabase = requireEnv("SURREAL_DATABASE");
 84→
 85→  const port = parsePositiveInteger(requireEnv("PORT"), "PORT");
 86→  const observerModelId = optionalEnv("OBSERVER_MODEL") ?? extractionModelId;
 87→  const scorerModelId = optionalEnv("SCORER_MODEL") ?? extractionModelId;
 88→  const githubWebhookSecret = optionalEnv("GITHUB_WEBHOOK_SECRET");
 89→  const betterAuthSecret = requireEnv("BETTER_AUTH_SECRET");
 90→  const betterAuthUrl = requireEnv("BETTER_AUTH_URL");
 91→  const githubClientId = requireEnv("GITHUB_CLIENT_ID");
 92→  const githubClientSecret = requireEnv("GITHUB_CLIENT_SECRET");
 93→  const anthropicApiUrl = optionalEnv("ANTHROPIC_API_URL") ?? "https://api.anthropic.com";
 94→  const anthropicApiKey = optionalEnv("ANTHROPIC_API_KEY");
 95→
 96→  const openRouterReasoning = inferenceProvider === "openrouter"
 97→    ? parseOpenRouterReasoning()
 98→    : undefined;
 99→
100→  const selfHosted = parseBooleanEnv("SELF_HOSTED");
101→  const worktreeManagerEnabled = parseBooleanEnv("WORKTREE_MANAGER_ENABLED");
102→  const orchestratorMockAgent = parseBooleanEnv("ORCHESTRATOR_MOCK_AGENT");
103→  const sandboxAgentEnabled = parseBooleanEnv("SANDBOX_AGENT_ENABLED");
104→  const sandboxAgentType = optionalEnv("SANDBOX_AGENT_TYPE");
105→  const internalWebhookSecret = optionalEnv("INTERNAL_WEBHOOK_SECRET");
106→  const toolEncryptionKey = optionalEnv("TOOL_ENCRYPTION_KEY");
107→  const baseUrl = optionalEnv("BRAIN_BASE_URL") ?? `http://localhost:${port}`;
108→
109→  const adminEmail = selfHosted
110→    ? requireSelfHostedEnv("ADMIN_EMAIL")
111→    : undefined;
112→  const adminPassword = selfHosted
113→    ? requireSelfHostedEnv("ADMIN_PASSWORD")
114→    : undefined;
115→
116→  return {
117→    inferenceProvider,
118→    ...(openRouterApiKey ? { openRouterApiKey } : {}),
119→    ...(ollamaBaseUrl ? { ollamaBaseUrl } : {}),
120→    chatAgentModelId,
121→    extractionModelId,
122→    pmAgentModelId,
123→    analyticsAgentModelId,
124→    extractionStoreThreshold,
125→    extractionDisplayThreshold,
126→    ...(openRouterReasoning ? { openRouterReasoning } : {}),
127→    surrealUrl,
128→    surrealUsername,
129→    surrealPassword,
130→    surrealNamespace,
131→    surrealDatabase,
132→    port,
133→    observerModelId,
134→    scorerModelId,
135→    ...(githubWebhookSecret ? { githubWebhookSecret } : {}),
136→    betterAuthSecret,
137→    betterAuthUrl,
138→    githubClientId,
139→    githubClientSecret,
140→    anthropicApiUrl,
141→    ...(anthropicApiKey ? { anthropicApiKey } : {}),
142→    selfHosted,
143→    ...(adminEmail ? { adminEmail } : {}),
144→    ...(adminPassword ? { adminPassword } : {}),
145→    worktreeManagerEnabled,
146→    orchestratorMockAgent,
147→    sandboxAgentEnabled,
148→    ...(sandboxAgentType ? { sandboxAgentType } : {}),
149→    ...(internalWebhookSecret ? { internalWebhookSecret } : {}),
150→    ...(toolEncryptionKey ? { toolEncryptionKey } : {}),
151→    baseUrl,
152→  };
153→}
154→
155→function optionalEnv(name: string): string | undefined {
156→  const value = Bun.env[name]?.trim();
157→  if (!value) return undefined;
158→  return value;
159→}
160→
161→function requireEnv(name: string): string {
162→  const value = Bun.env[name];
163→  if (!value || value.trim().length === 0) {
164→    throw new Error(`${name} is required`);
165→  }
166→
167→  return value;
168→}
169→
170→function parsePositiveInteger(value: string, envName: string): number {
171→  const parsed = Number(value);
172→  if (!Number.isInteger(parsed) || parsed < 1) {
173→    throw new Error(`${envName} must be a positive integer`);
174→  }
175→  return parsed;
176→}
177→
178→function parseUnitInterval(value: string, envName: string): number {
179→  const parsed = Number(value);
180→  if (!Number.isFinite(parsed) || parsed < 0 || parsed > 1) {
181→    throw new Error(`${envName} must be a number between 0 and 1`);
182→  }
183→
184→  return parsed;
185→}
186→
187→function parseInferenceProvider(): InferenceProvider {
188→  const value = Bun.env.INFERENCE_PROVIDER?.trim().toLowerCase();
189→  if (!value || value === "openrouter") return "openrouter";
190→  if (value === "ollama") return "ollama";
191→  throw new Error("INFERENCE_PROVIDER must be one of: openrouter, ollama");
192→}
193→
194→function parseBooleanEnv(name: string): boolean {
195→  const value = Bun.env[name]?.trim().toLowerCase();
196→  return value === "true";
197→}
198→
199→function requireSelfHostedEnv(name: string): string {
200→  const value = Bun.env[name]?.trim();
201→  if (!value) {
202→    throw new Error(`${name} is required when SELF_HOSTED=true`);
203→  }
204→  return value;
205→}
206→
207→function parseOpenRouterReasoning(): OpenRouterReasoningOptions | undefined {
208→  const effortValue = Bun.env.OPENROUTER_REASONING_EFFORT;
209→  const maxTokensValue = Bun.env.OPENROUTER_REASONING_MAX_TOKENS;
210→
211→  if (!effortValue && !maxTokensValue) {
212→    return undefined;
213→  }
214→
215→  const reasoning: OpenRouterReasoningOptions = {};
216→
217→  if (effortValue) {
218→    const allowedEfforts: OpenRouterReasoningEffort[] = ["xhigh", "high", "medium", "low", "minimal", "none"];
219→
220→    if (!allowedEfforts.includes(effortValue as OpenRouterReasoningEffort)) {
221→      throw new Error("OPENROUTER_REASONING_EFFORT must be one of xhigh, high, medium, low, minimal, none");
222→    }
223→    reasoning.effort = effortValue as OpenRouterReasoningEffort;
224→  }
225→
226→  if (maxTokensValue) {
227→    const parsed = Number(maxTokensValue);
228→    if (!Number.isFinite(parsed) || parsed < 1) {
229→      throw new Error("OPENROUTER_REASONING_MAX_TOKENS must be a positive number");
230→    }
231→    reasoning.max_tokens = parsed;
232→  }
233→
234→  return reasoning;
235→}
