10→export type InflightTracker = {
11→  track(promise: Promise<unknown>): void;
12→  drain(timeoutMs?: number): Promise<void>;
13→};
14→
15→export function createInflightTracker(): InflightTracker {
16→  const pending = new Set<Promise<unknown>>();
17→  return {
18→    track(promise) {
19→      pending.add(promise);
20→      promise.finally(() => pending.delete(promise));
21→    },
22→    async drain(timeoutMs = 30_000) {
23→      if (pending.size === 0) return;
24→      await Promise.race([
25→        Promise.allSettled([...pending]),
26→        new Promise<void>((resolve) => setTimeout(resolve, timeoutMs)),
27→      ]);
28→    },
29→  };
30→}
