 39→async function createTestWorkspace(
 40→  baseUrl: string,
 41→  user: { headers: Record<string, string> },
 42→  surreal: AcceptanceTestRuntime["surreal"],
 43→): Promise<{ workspaceId: string }> {
 44→  const response = await fetch(`${baseUrl}/api/workspaces`, {
 45→    method: "POST",
 46→    headers: { "Content-Type": "application/json", ...user.headers },
 47→    body: JSON.stringify({ name: `Sandbox Test ${crypto.randomUUID()}` }),
 48→  });
 49→  if (!response.ok) {
 50→    throw new Error(`Failed to create workspace: ${response.status}`);
 51→  }
 52→  const body = (await response.json()) as { workspaceId: string };
 53→
 54→  // Set repo_path so the orchestrator can create worktrees
 55→  const workspaceRecord = new RecordId("workspace", body.workspaceId);
 56→  await surreal.query(
 57→    `UPDATE $ws SET repo_path = $path;`,
 58→    { ws: workspaceRecord, path: process.cwd() },
 59→  );
 60→
 61→  return { workspaceId: body.workspaceId };
 62→}
 63→
 64→async function createReadyTask(
 65→  surreal: AcceptanceTestRuntime["surreal"],
 66→  workspaceId: string,
 67→  task: { title: string; description: string },
 68→): Promise<{ taskId: string }> {
 69→  const taskId = crypto.randomUUID();
 70→  const taskRecord = new RecordId("task", taskId);
 71→  const workspaceRecord = new RecordId("workspace", workspaceId);
 72→
 73→  await surreal.query(`CREATE $task CONTENT $content;`, {
 74→    task: taskRecord,
 75→    content: {
 76→      title: task.title,
 77→      description: task.description,
 78→      status: "ready",
 79→      workspace: workspaceRecord,
 80→      created_at: new Date(),
 81→    },
 82→  });
 83→
 84→  return { taskId };
 85→}
 86→
 87→async function assignTaskToSandboxAgent(
 88→  baseUrl: string,
 89→  user: { headers: Record<string, string> },
 90→  workspaceId: string,
 91→  taskId: string,
 92→): Promise<{ agentSessionId: string; streamUrl: string }> {
 93→  const response = await fetch(
 94→    `${baseUrl}/api/orchestrator/${workspaceId}/assign`,
 95→    {
 96→      method: "POST",
 97→      headers: { "Content-Type": "application/json", ...user.headers },
 98→      body: JSON.stringify({ taskId }),
 99→    },
100→  );
101→  if (!response.ok) {
102→    const body = await response.text();
103→    throw new Error(`Failed to assign task: ${response.status} ${body}`);
104→  }
105→  return (await response.json()) as { agentSessionId: string; streamUrl: string };
106→}
107→
108→async function sendPrompt(
109→  baseUrl: string,
110→  user: { headers: Record<string, string> },
111→  workspaceId: string,
112→  sessionId: string,
113→  text: string,
114→): Promise<Response> {
115→  return fetch(
116→    `${baseUrl}/api/orchestrator/${workspaceId}/sessions/${sessionId}/prompt`,
117→    {
118→      method: "POST",
119→      headers: { "Content-Type": "application/json", ...user.headers },
120→      body: JSON.stringify({ text }),
121→    },
122→  );
123→}
124→
125→async function getSessionStatus(
126→  baseUrl: string,
127→  user: { headers: Record<string, string> },
128→  workspaceId: string,
129→  sessionId: string,
130→): Promise<{ orchestratorStatus: string; sessionType?: string }> {
131→  const response = await fetch(
132→    `${baseUrl}/api/orchestrator/${workspaceId}/sessions/${sessionId}`,
133→    { headers: user.headers },
134→  );
135→  if (!response.ok) {
136→    throw new Error(`Failed to get session status: ${response.status}`);
137→  }
138→  return (await response.json()) as { orchestratorStatus: string; sessionType?: string };
139→}
140→
141→async function querySessionFromDb(
142→  surreal: AcceptanceTestRuntime["surreal"],
143→  sessionId: string,
144→): Promise<Record<string, unknown> | undefined> {
145→  const [rows] = await surreal.query<[Array<Record<string, unknown>>]>(
146→    `SELECT * FROM $record;`,
147→    { record: new RecordId("agent_session", sessionId) },
148→  );
149→  return rows[0];
150→}
