 14→
 15→type SurrealSpy = {
 16→  stub: unknown;
 17→  updates: Array<{ record: unknown; merge: unknown }>;
 18→  selects: Array<{ record: unknown }>;
 19→};
 20→
 21→function createSurrealSpy(responses: {
 22→  sessionSelect?: Record<string, unknown>;
 23→}): SurrealSpy {
 24→  const spy: SurrealSpy = {
 25→    stub: undefined,
 26→    updates: [],
 27→    selects: [],
 28→  };
 29→
 30→  spy.stub = {
 31→    query(sql: string, _bindings?: Record<string, unknown>) {
 32→      if (sql.includes("FROM $taskRecord")) {
 33→        return Promise.resolve([[]]);
 34→      }
 35→      if (sql.includes("orchestrator_status") && sql.includes("agent_session")) {
 36→        return Promise.resolve([[]]);
 37→      }
 38→      return Promise.resolve([[]]);
 39→    },
 40→    update(record: unknown) {
 41→      return {
 42→        merge(data: unknown) {
 43→          spy.updates.push({ record, merge: data });
 44→          return Promise.resolve({ id: record, ...(data as object) });
 45→        },
 46→      };
 47→    },
 48→    select(record: unknown) {
 49→      spy.selects.push({ record });
 50→      return Promise.resolve(responses.sessionSelect ?? undefined);
 51→    },
 52→    delete(_record: unknown) {
 53→      return Promise.resolve();
 54→    },
 55→  };
 56→
 57→  return spy;
 58→}
 59→
 60→function spawnAgentStub() {
 61→  const abortCalls: string[] = [];
 62→  return {
 63→    spawn: (config: AgentSpawnConfig) => ({
 64→      messages: (async function* () {})(),
 65→      abort: () => {
 66→        abortCalls.push("aborted");
 67→      },
 68→    }),
 69→    abortCalls,
 70→  };
 71→}
