104→    return (await request.json()) as T;
105→  } catch {
106→    return undefined;
107→  }
108→}
109→
110→function extractAuthToken(request: Request): string {
111→  return request.headers.get("Cookie") ?? "";
112→}
113→
114→// ---------------------------------------------------------------------------
115→// Response builders (pure)
116→// ---------------------------------------------------------------------------
117→
118→function assignResponse(
119→  workspaceId: string,
120→  value: { agentSessionId: string; streamId: string; worktreeBranch: string },
121→): Response {
122→  return jsonResponse(
123→    {
124→      agentSessionId: value.agentSessionId,
125→      streamId: value.streamId,
126→      streamUrl: `/api/orchestrator/${workspaceId}/sessions/${value.agentSessionId}/stream`,
127→    },
128→    200,
129→  );
130→}
131→
132→function statusResponse(
133→  sessionId: string,
134→  value: {
135→    orchestratorStatus: string;
136→    worktreeBranch?: string;
137→    worktreePath?: string;
138→    startedAt?: string;
139→    lastEventAt?: string;
140→    error?: string;
141→  },
142→): Response {
143→  return jsonResponse(
144→    {
145→      agentSessionId: sessionId,
146→      orchestratorStatus: value.orchestratorStatus,
147→      ...pickDefined({
148→        worktreeBranch: value.worktreeBranch,
149→        worktreePath: value.worktreePath,
150→        startedAt: value.startedAt,
151→        lastEventAt: value.lastEventAt,
152→        error: value.error,
153→      }),
154→    },
155→    200,
156→  );
157→}
158→
159→function acceptResponse(): Response {
160→  return jsonResponse({ accepted: true, taskStatus: "done" }, 200);
161→}
162→
163→function abortResponse(): Response {
164→  return jsonResponse({ aborted: true, taskStatus: "ready" }, 200);
165→}
166→
167→function reviewResponse(value: {
168→  taskTitle: string;
169→  diff: unknown;
170→  session: unknown;
171→}): Response {
172→  return jsonResponse(value, 200);
173→}
174→
175→function rejectResponse(): Response {
176→  return jsonResponse({ rejected: true, continuing: true }, 200);
177→}
178→
179→function promptResponse(): Response {
180→  return jsonResponse({ delivered: true }, 202);
181→}
182→
183→function sessionErrorResponse(error: {
184→  message: string;
185→  httpStatus: number;
186→}): Response {
187→  return jsonError(error.message, error.httpStatus);
188→}
189→
190→// ---------------------------------------------------------------------------
191→// Route handler factory
192→// ---------------------------------------------------------------------------
193→
194→export function createOrchestratorRouteHandlers(deps: OrchestratorRouteDeps) {
195→  const assign: RouteHandler = async (request) => {
196→    const workspaceId = request.params.workspaceId;
197→    const body = await parseJsonBody<AssignBody>(request);
198→
199→    if (!body?.taskId) {
200→      return jsonError("taskId is required", 400);
201→    }
202→
203→    const authToken = extractAuthToken(request);
204→    const result = await deps.createSession(workspaceId, body.taskId, authToken);
205→
206→    if (!result.ok) {
207→      return sessionErrorResponse(result.error);
208→    }
209→
210→    return assignResponse(workspaceId, result.value);
211→  };
212→
213→  const status: RouteHandler = async (request) => {
214→    const sessionId = request.params.sessionId;
215→    const result = await deps.getSessionStatus(sessionId);
216→
217→    if (!result.ok) {
218→      return sessionErrorResponse(result.error);
219→    }
220→
221→    return statusResponse(sessionId, result.value);
222→  };
223→
224→  const accept: RouteHandler = async (request) => {
225→    const sessionId = request.params.sessionId;
226→    const body = await parseJsonBody<AcceptBody>(request);
227→    const summary = body?.summary ?? "";
228→
229→    const result = await deps.acceptSession(sessionId, summary);
230→
231→    if (!result.ok) {
232→      return sessionErrorResponse(result.error);
233→    }
234→
235→    return acceptResponse();
236→  };
237→
238→  const abort: RouteHandler = async (request) => {
239→    const sessionId = request.params.sessionId;
240→    const result = await deps.abortSession(sessionId);
241→
242→    if (!result.ok) {
243→      return sessionErrorResponse(result.error);
244→    }
245→
246→    return abortResponse();
247→  };
248→
249→  const review: RouteHandler = async (request) => {
250→    const sessionId = request.params.sessionId;
251→    const result = await deps.getReview(sessionId);
252→
253→    if (!result.ok) {
254→      return sessionErrorResponse(result.error);
255→    }
256→
257→    return reviewResponse(result.value);
258→  };
259→
260→  const reject: RouteHandler = async (request) => {
261→    const sessionId = request.params.sessionId;
262→    const body = await parseJsonBody<RejectBody>(request);
263→
264→    if (!body?.feedback || body.feedback.trim() === "") {
265→      return jsonError("feedback is required", 400);
266→    }
267→
268→    const result = await deps.rejectSession(sessionId, body.feedback);
269→
270→    if (!result.ok) {
271→      return sessionErrorResponse(result.error);
272→    }
273→
274→    return rejectResponse();
275→  };
276→
277→  const prompt: RouteHandler = async (request) => {
278→    const sessionId = request.params.sessionId;
279→    const body = await parseJsonBody<PromptBody>(request);
280→
281→    if (!body?.text || body.text.trim() === "") {
282→      return jsonError("text is required", 400);
283→    }
284→
285→    const result = await deps.sendPrompt(sessionId, body.text);
286→
287→    if (!result.ok) {
288→      return sessionErrorResponse(result.error);
289→    }
290→
291→    return promptResponse();
292→  };
293→
294→  return { assign, status, accept, abort, review, reject, prompt };
295→}
296→
297→// ---------------------------------------------------------------------------
298→// SSE stream route handler factory
299→// ---------------------------------------------------------------------------
300→
301→export type StreamRouteDeps = {
302→  sseRegistry: SseRegistry;
303→};
304→
305→export function createStreamRouteHandler(deps: StreamRouteDeps) {
306→  const stream: RouteHandler = async (request) => {
307→    const sessionId = request.params.sessionId;
308→
309→    if (!sessionId) {
310→      return jsonError("sessionId is required", 400);
311→    }
312→
313→    const streamId = `stream-${sessionId}`;
314→    return deps.sseRegistry.handleStreamRequest(streamId);
315→  };
316→
317→  return { stream };
318→}
319→
320→// ---------------------------------------------------------------------------
321→// Wiring factory: creates OrchestratorRouteDeps from server dependencies
322→// ---------------------------------------------------------------------------
323→
324→export type OrchestratorWiringDeps = {
325→  surreal: import("surrealdb").Surreal;
326→  shellExec: import("./worktree-manager").ShellExec;
327→  brainBaseUrl: string;
328→  extractionModel: import("../runtime/types").ServerDependencies["extractionModel"];
329→  asSigningKey: import("../oauth/as-key-management").AsSigningKey;
330→  sseRegistry?: SseRegistry;
331→  queryFn: import("./spawn-agent").QueryFn;
332→  auth: { api: { getSession: (opts: { headers: Headers }) => Promise<{ user?: { id?: string } } | null> } };
333→  mockAgent: boolean;
334→  sandboxAgentAdapter?: import("./sandbox-adapter").SandboxAgentAdapter;
335→  sandboxAgentType?: string;
336→};
337→
338→export function wireOrchestratorRoutes(
339→  wiringDeps: OrchestratorWiringDeps,
340→): {
341→  assign: RouteHandler;
342→  status: RouteHandler;
343→  accept: RouteHandler;
344→  abort: RouteHandler;
345→  review: RouteHandler;
346→  reject: RouteHandler;
347→  prompt: RouteHandler;
348→  stream?: RouteHandler;
349→} {
350→  const proxyTokenTtlDays = readProxyTokenTtlDays();
351→
352→  const issueProxyTokenForWorkspace = async (
353→    workspaceId: string,
354→    authToken: string,
355→  ): Promise<{ proxyToken: string; identityId: string }> => {
356→    const sessionHeaders = new Headers(authToken ? { Cookie: authToken } : undefined);
357→    const session = await wiringDeps.auth.api.getSession({ headers: sessionHeaders });
358→    const personId = session?.user?.id;
359→    if (!personId) {
360→      throw new Error("Failed to issue proxy token: authentication required");
361→    }
362→
363→    const personRecord = new RecordId("person", personId);
364→    const workspaceRecord = new RecordId("workspace", workspaceId);
365→    const [identityRows] = await wiringDeps.surreal.query<[Array<RecordId<"identity", string>>]>(
366→      `SELECT VALUE in FROM member_of WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person) AND out = $ws LIMIT 1;`,
367→      { person: personRecord, ws: workspaceRecord },
368→    );
369→    const identityRecord = identityRows[0];
370→    if (!identityRecord) {
371→      throw new Error(`Failed to issue proxy token: workspace membership required for ${workspaceId}`);
372→    }
373→    const identityId = identityRecord.id as string;
374→
375→    const rawToken = generateProxyToken();
376→    const tokenHash = hashProxyToken(rawToken);
377→    const expiresAt = computeExpiresAt(proxyTokenTtlDays);
378→
379→    await wiringDeps.surreal.query(
380→      `BEGIN TRANSACTION;
381→       UPDATE proxy_token SET revoked = true WHERE identity = $identity AND workspace = $ws AND revoked = false;
382→       CREATE proxy_token CONTENT {
383→         token_hash: $hash,
384→         workspace: $ws,
385→         identity: $identity,
386→         expires_at: $expires,
387→         created_at: time::now(),
388→         revoked: false
389→       };
390→       COMMIT TRANSACTION;`,
391→      {
392→        hash: tokenHash,
393→        ws: workspaceRecord,
394→        identity: identityRecord,
395→        expires: expiresAt,
396→      },
397→    );
398→
399→    return { proxyToken: rawToken, identityId };
400→  };
401→
402→  const issueBrainMcpAuthEnv = async (
403→    workspaceId: string,
404→    identityId: string,
405→    intentGoal: string,
406→    intentReasoning: string,
407→  ): Promise<Record<string, string>> => {
408→    const dpopKeys = await generateKeyPair();
409→    const intentResult = await submitIntentForAuthorization(
410→      {
411→        workspace_id: workspaceId,
412→        identity_id: identityId,
413→        authorization_details: CLI_AUTHORIZATION_DETAILS,
414→        dpop_jwk_thumbprint: dpopKeys.thumbprint,
415→        goal: intentGoal,
416→        reasoning: intentReasoning,
417→      },
418→      {
419→        surreal: wiringDeps.surreal,
420→        extractionModel: wiringDeps.extractionModel,
421→      },
422→    );
423→
424→    let intentStatus: string = intentResult.status;
425→    if (intentStatus === "pending_auth") {
426→      const evaluation = await evaluatePendingIntent(
427→        intentResult.intentId,
428→        {
429→          surreal: wiringDeps.surreal,
430→          extractionModel: wiringDeps.extractionModel,
431→          llmEvaluator: async () => ({
432→            decision: "APPROVE",
433→            risk_score: 0,
434→            reason: "Approved from explicit authenticated orchestrator task assignment",
435→            reasoning:
436→              "User explicitly assigned this task in the orchestrator UI. " +
437→              "Bootstrap MCP token is required to complete the assigned task.",
438→          }),
439→        },
440→      );
441→      if (!evaluation.ok) {
442→        throw new Error(
443→          `Failed to evaluate MCP auth intent: ${evaluation.httpStatus} ${evaluation.error}`,
444→        );
445→      }
446→      intentStatus = evaluation.value.status;
447→    }
448→
449→    if (intentStatus !== "authorized") {
450→      throw new Error(`MCP auth intent is "${intentStatus}" (expected "authorized")`);
451→    }
452→
453→    const tokenResult = await exchangeIntentForToken({
454→      surreal: wiringDeps.surreal,
455→      asSigningKey: wiringDeps.asSigningKey,
456→      intentId: intentResult.intentId,
457→      authorizationDetails: CLI_AUTHORIZATION_DETAILS,
458→      proofThumbprint: dpopKeys.thumbprint,
459→    });
460→
461→    if (!tokenResult.ok) {
462→      throw new Error(
463→        `Failed to exchange MCP auth token: ${tokenResult.httpStatus} ${tokenResult.errorDescription}`,
464→      );
465→    }
466→
467→    const dpopTokenExpiresAt = Math.floor(Date.now() / 1000) + tokenResult.value.expiresIn;
468→
469→    return {
470→      BRAIN_CLIENT_ID: "orchestrator-session",
471→      BRAIN_ACCESS_TOKEN: "orchestrator-session",
472→      BRAIN_REFRESH_TOKEN: "orchestrator-session",
473→      BRAIN_TOKEN_EXPIRES_AT: String(dpopTokenExpiresAt),
474→      BRAIN_DPOP_PRIVATE_JWK: JSON.stringify(dpopKeys.privateJwk),
475→      BRAIN_DPOP_PUBLIC_JWK: JSON.stringify(dpopKeys.publicJwk),
476→      BRAIN_DPOP_THUMBPRINT: dpopKeys.thumbprint,
477→      BRAIN_DPOP_ACCESS_TOKEN: tokenResult.value.accessToken,
478→      BRAIN_DPOP_TOKEN_EXPIRES_AT: String(dpopTokenExpiresAt),
479→    };
480→  };
481→
482→  // Workspace access guard — resolves user from session cookie, checks membership
483→  const validateWorkspaceAccess = async (request: Request, workspaceId: string): Promise<Response | undefined> => {
484→    const session = await wiringDeps.auth.api.getSession({ headers: request.headers });
485→    if (!session?.user?.id) {
486→      return jsonError("authentication required", 401);
487→    }
488→    const { RecordId } = await import("surrealdb");
489→    const personRecord = new RecordId("person", session.user.id);
490→    const workspaceRecord = new RecordId("workspace", workspaceId);
491→    // member_of is identity->workspace; resolve person->identity via identity_person subquery
492→    const [memberRows] = await wiringDeps.surreal.query<[Array<{ role: string }>]>(
493→      `SELECT role FROM member_of WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person) AND out = $ws LIMIT 1;`,
494→      { person: personRecord, ws: workspaceRecord },
495→    );
496→    if (!memberRows || memberRows.length === 0) {
497→      return jsonError("not a member of this workspace", 403);
498→    }
499→    return undefined;
500→  };
501→
502→  // Lazy imports to keep module boundary clean
503→  const lifecycleImport = import("./session-lifecycle");
504→  const queriesImport = import("../mcp/mcp-queries");
505→  const guardImport = import("./assignment-guard");
506→  const stallDetectorImport = import("./stall-detector");
507→
508→  // Helper: resolve repo_path from workspace record
509→  const resolveRepoRoot = async (workspaceRecord: import("surrealdb").RecordId<"workspace", string>): Promise<string> => {
510→    const [rows] = await wiringDeps.surreal.query<[Array<{ repo_path?: string }>]>(
511→      `SELECT repo_path FROM $ws;`,
512→      { ws: workspaceRecord },
513→    );
514→    const repoPath = rows[0]?.repo_path;
515→    if (!repoPath) {
516→      throw new Error(`Workspace ${workspaceRecord.id} has no repo_path configured`);
517→    }
518→    return repoPath;
519→  };
520→
521→  const buildTaskScopedIntentContext = async (
522→    taskId: string,
523→  ): Promise<{ goal: string; reasoning: string }> => {
524→    const taskRecord = new RecordId("task", taskId);
525→    const [taskRows] = await wiringDeps.surreal.query<[Array<{ title?: string; description?: string }>]>(
526→      `SELECT title, description FROM $task LIMIT 1;`,
527→      { task: taskRecord },
528→    );
529→    const taskTitle = taskRows[0]?.title?.trim();
530→    const taskDescription = taskRows[0]?.description?.trim();
531→    const taskLabel = taskTitle && taskTitle.length > 0 ? taskTitle : taskId;
532→    const descriptionSuffix = taskDescription && taskDescription.length > 0
533→      ? ` Task description: ${taskDescription}`
534→      : "";
535→
536→    return {
537→      goal: `Complete task: ${taskLabel}`,
538→      reasoning: `Use Brain MCP tools required to complete task "${taskLabel}" in this workspace.${descriptionSuffix}`,
539→    };
540→  };
541→
542→  // Resolve adapter: real SDK adapter from deps > mock adapter > none (legacy spawn)
543→  const sandboxAdapterImport = wiringDeps.sandboxAgentAdapter
544→    ? Promise.resolve(wiringDeps.sandboxAgentAdapter)
545→    : wiringDeps.mockAgent
546→      ? import("./sandbox-adapter").then((mod) => mod.createMockAdapter())
547→      : undefined;
548→
549→  const spawnAgentImport = wiringDeps.mockAgent
550→    ? Promise.resolve({
551→        createSpawnAgent: (_qfn: import("./spawn-agent").QueryFn): import("./spawn-agent").SpawnAgentFn =>
552→          () => ({
553→            messages: (async function* () {})(),
554→            abort: () => {},
555→          }),
556→      })
557→    : import("./spawn-agent");
558→
559→  const routeDeps: OrchestratorRouteDeps = {
560→    createSession: async (workspaceId, taskId, authToken) => {
561→      const adapter = sandboxAdapterImport ? await sandboxAdapterImport : undefined;
562→      const [lifecycle, queries, guard, { createSpawnAgent }, stallDetector] = await Promise.all([
563→        lifecycleImport,
564→        queriesImport,
565→        guardImport,
566→        spawnAgentImport,
567→        stallDetectorImport,
568→      ]);
569→
570→      // When using adapter (sandbox path), skip proxy token / MCP auth setup
571→      // — the sandbox adapter manages its own auth. In mock mode, this avoids
572→      // requiring full OAuth infrastructure in acceptance tests.
573→      let proxyToken: string | undefined;
574→      let brainIdentityId: string | undefined;
575→      let brainAuthEnv: Record<string, string> = {};
576→
577→      if (!adapter) {
578→        try {
579→          const tokenResult = await issueProxyTokenForWorkspace(workspaceId, authToken);
580→          proxyToken = tokenResult.proxyToken;
581→          brainIdentityId = tokenResult.identityId;
582→          const intentContext = await buildTaskScopedIntentContext(taskId);
583→          brainAuthEnv = await issueBrainMcpAuthEnv(
584→            workspaceId,
585→            brainIdentityId,
586→            intentContext.goal,
587→            intentContext.reasoning,
588→          );
589→        } catch (err) {
590→          return {
591→            ok: false,
592→            error: {
593→              code: "SESSION_ERROR",
594→              message: err instanceof Error ? err.message : "Failed to issue proxy token",
595→              httpStatus: 500,
596→            },
597→          };
598→        }
599→      }
600→
601→      const spawnAgent = createSpawnAgent(wiringDeps.queryFn);
602→      const result = await lifecycle.createOrchestratorSession({
603→        surreal: wiringDeps.surreal,
604→        shellExec: wiringDeps.shellExec,
605→        brainBaseUrl: wiringDeps.brainBaseUrl,
606→        brainIdentityId,
607→        brainEnv: brainAuthEnv,
608→        anthropicBaseUrl: proxyToken ? `${wiringDeps.brainBaseUrl}/proxy/llm/anthropic` : undefined,
609→        anthropicCustomHeaders: proxyToken ? `X-Brain-Auth: ${proxyToken}` : undefined,
610→        workspaceId,
611→        taskId,
612→        authToken,
613→        validateAssignment: guard.validateAssignment,
614→        createAgentSession: queries.createAgentSession,
615→        spawnAgent,
616→        adapter,
617→        sandboxAgentType: wiringDeps.sandboxAgentType,
618→      });
619→
620→      // Wire SSE stream + event iteration on success
621→      if (result.ok && wiringDeps.sseRegistry) {
622→        const { agentSessionId, streamId, sessionHandle } = result.value;
623→        wiringDeps.sseRegistry.registerMessage(streamId);
624→
625→        // Adapter path: wire sandbox event bridge
626→        if (sessionHandle && adapter) {
627→          const { createSandboxEventBridge } = await import("./sandbox-event-bridge");
628→          const bridge = createSandboxEventBridge(
629→            {
630→              emitEvent: wiringDeps.sseRegistry.emitEvent,
631→              updateLastEventAt: async (sid) => {
632→                const rec = new RecordId("agent_session", sid);
633→                await wiringDeps.surreal.update(rec).merge({
634→                  last_event_at: new Date(),
635→                });
636→              },
637→              notifyStallDetector: () => {
638→                // Stall detector integration deferred to later step
639→              },
640→            },
641→            streamId,
642→            agentSessionId,
643→          );
644→          sessionHandle.onEvent((event) => {
645→            bridge.handleEvent(event as import("./sandbox-event-bridge").SandboxEvent);
646→          });
647→        } else {
648→          // Legacy path: SDK message stream iteration
649→          const handle = lifecycle.getHandle(agentSessionId);
650→          if (handle) {
651→            const { RecordId } = await import("surrealdb");
652→            lifecycle.startEventIteration(
653→              {
654→                emitEvent: wiringDeps.sseRegistry.emitEvent,
655→                updateSessionStatus: async (sid, status, error) => {
656→                  const rec = new RecordId("agent_session", sid);
657→                  await wiringDeps.surreal.update(rec).merge({
658→                    orchestrator_status: status,
659→                    ...(error !== undefined ? { error_message: error } : {}),
660→                  });
661→                },
662→                updateLastEventAt: async (sid) => {
663→                  const rec = new RecordId("agent_session", sid);
664→                  await wiringDeps.surreal.update(rec).merge({
665→                    last_event_at: new Date(),
666→                  });
667→                },
668→                getSessionStatus: async (sid) => {
669→                  const rec = new RecordId("agent_session", sid);
670→                  const row = await wiringDeps.surreal.select(rec) as { orchestrator_status?: string } | undefined;
671→                  return (row?.orchestrator_status ?? "error") as import("./types").OrchestratorStatus;
672→                },
673→                startStallDetector: (sid, stId) =>
674→                  stallDetector.startStallDetector(
675→                    {
676→                      abortSession: async (abortSid) => {
677→                        const abortResult = await lifecycle.abortOrchestratorSession({
678→                          surreal: wiringDeps.surreal,
679→                          shellExec: wiringDeps.shellExec,
680→                          resolveRepoRoot,
681→                          sessionId: abortSid,
682→                          endAgentSession: queries.endAgentSession,
683→                        });
684→                        return abortResult;
685→                      },
686→                      createObservation: async () => {},
687→                      emitEvent: wiringDeps.sseRegistry!.emitEvent,
688→                    },
689→                    stallDetector.DEFAULT_STALL_CONFIG,
690→                    sid,
691→                    stId,
692→                  ),
693→              },
694→              handle.messages,
695→              streamId,
696→              agentSessionId,
697→            );
698→          }
699→        }
700→      }
701→
702→      return result;
703→    },
704→
705→    getSessionStatus: async (sessionId) => {
706→      const lifecycle = await lifecycleImport;
707→      return lifecycle.getOrchestratorSessionStatus({
708→        surreal: wiringDeps.surreal,
709→        sessionId,
710→      });
711→    },
712→
713→    abortSession: async (sessionId) => {
714→      const adapter = sandboxAdapterImport ? await sandboxAdapterImport : undefined;
715→      const [lifecycle, queries] = await Promise.all([
716→        lifecycleImport,
717→        queriesImport,
718→      ]);
719→      return lifecycle.abortOrchestratorSession({
720→        surreal: wiringDeps.surreal,
721→        shellExec: wiringDeps.shellExec,
722→        resolveRepoRoot,
723→        sessionId,
724→        adapter,
725→        endAgentSession: queries.endAgentSession,
726→      });
727→    },
728→
729→    acceptSession: async (sessionId, summary) => {
730→      const [lifecycle, queries] = await Promise.all([
731→        lifecycleImport,
732→        queriesImport,
733→      ]);
734→      return lifecycle.acceptOrchestratorSession({
735→        surreal: wiringDeps.surreal,
736→        sessionId,
737→        summary,
738→        endAgentSession: queries.endAgentSession,
739→      });
740→    },
741→
742→    getReview: async (sessionId) => {
743→      const [lifecycle, worktreeManager] = await Promise.all([
744→        lifecycleImport,
745→        import("./worktree-manager"),
746→      ]);
747→      return lifecycle.getOrchestratorReview({
748→        surreal: wiringDeps.surreal,
749→        sessionId,
750→        resolveRepoRoot,
751→        getDiff: (repoRoot: string, branchName: string) =>
752→          worktreeManager.getDiff(wiringDeps.shellExec, repoRoot, branchName),
753→        getTaskTitle: async (taskId: string) => {
754→          const { RecordId } = await import("surrealdb");
755→          const taskRecord = new RecordId("task", taskId);
756→          const rows = (await wiringDeps.surreal.query(
757→            `SELECT title FROM $task;`,
758→            { task: taskRecord },
759→          )) as Array<Array<{ title: string }>>;
760→          return rows[0]?.[0]?.title ?? "";
761→        },
762→      });
763→    },
764→
765→    rejectSession: async (sessionId, feedback) => {
766→      const lifecycle = await lifecycleImport;
767→      return lifecycle.rejectOrchestratorSession({
768→        surreal: wiringDeps.surreal,
769→        sessionId,
770→        feedback,
771→      });
772→    },
773→
774→    sendPrompt: async (sessionId, text) => {
775→      const adapter = sandboxAdapterImport ? await sandboxAdapterImport : undefined;
776→      const lifecycle = await lifecycleImport;
777→      return lifecycle.sendSessionPrompt({
778→        surreal: wiringDeps.surreal,
779→        sessionId,
780→        text,
781→        adapter,
782→      });
783→    },
784→  };
785→
786→  const handlers = createOrchestratorRouteHandlers(routeDeps);
787→
788→  // Wrap handler with workspace access check
789→  const withWorkspaceAccess = (handler: RouteHandler): RouteHandler => async (request) => {
790→    const workspaceId = request.params.workspaceId;
791→    if (workspaceId) {
792→      const accessError = await validateWorkspaceAccess(request, workspaceId);
793→      if (accessError) return accessError;
794→    }
795→    return handler(request);
796→  };
797→
798→  const streamHandler = wiringDeps.sseRegistry
799→    ? createStreamRouteHandler({ sseRegistry: wiringDeps.sseRegistry })
800→    : undefined;
801→
802→  return {
803→    assign: withTracing("orchestrator.assign", "POST", withWorkspaceAccess(handlers.assign)),
804→    status: withTracing("orchestrator.status", "GET", withWorkspaceAccess(handlers.status)),
805→    accept: withTracing("orchestrator.accept", "POST", withWorkspaceAccess(handlers.accept)),
806→    abort: withTracing("orchestrator.abort", "POST", withWorkspaceAccess(handlers.abort)),
807→    review: withTracing("orchestrator.review", "GET", withWorkspaceAccess(handlers.review)),
808→    reject: withTracing("orchestrator.reject", "POST", withWorkspaceAccess(handlers.reject)),
809→    prompt: withTracing("orchestrator.prompt", "POST", withWorkspaceAccess(handlers.prompt)),
810→    ...(streamHandler
811→      ? { stream: withTracing("orchestrator.stream", "GET", withWorkspaceAccess(streamHandler.stream)) }
812→      : {}),
813→  };
814→}
