290→function requireWorkspace(session: SessionRow, sessionId: string): RecordId<"workspace", string> {
291→  if (!session.workspace) {
292→    throw new Error(`agent_session ${sessionId} missing workspace — data corruption`);
293→  }
294→  return session.workspace as RecordId<"workspace", string>;
295→}
