301→function appendOrchestratorProxyHeaders(
302→  baseHeaders: string,
303→  taskId: string,
304→  sessionId: string,
305→): string {
306→  const lines = baseHeaders
307→    .split(/\r?\n/)
308→    .map((line) => line.trim())
309→    .filter((line) => line.length > 0);
310→
311→  const headerMap = new Map<string, string>();
312→  for (const line of lines) {
313→    const sep = line.indexOf(":");
314→    if (sep <= 0) {
315→      continue;
316→    }
317→    const name = line.slice(0, sep).trim();
318→    const value = line.slice(sep + 1).trim();
319→    if (name.length === 0 || value.length === 0) {
320→      continue;
321→    }
322→    headerMap.set(name.toLowerCase(), `${name}: ${value}`);
323→  }
324→
325→  headerMap.set("x-brain-task", `X-Brain-Task: ${taskId}`);
326→  headerMap.set("x-brain-session", `X-Brain-Session: ${sessionId}`);
327→
328→  return Array.from(headerMap.values()).join("\n");
329→}
