661→// ---------------------------------------------------------------------------
662→// abortOrchestratorSession
663→// ---------------------------------------------------------------------------
664→
665→type AbortSessionInput = {
666→  surreal: Surreal;
667→  shellExec: ShellExec;
668→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
669→  sessionId: string;
670→  adapter?: SandboxAgentAdapter;
671→  endAgentSession: (input: {
672→    surreal: Surreal;
673→    workspaceRecord: RecordId<"workspace", string>;
674→    sessionId: string;
675→    summary: string;
676→  }) => Promise<{ session_id: string; ended: boolean }>;
677→};
678→
679→export async function abortOrchestratorSession(
680→  input: AbortSessionInput,
681→): Promise<AbortSessionResult> {
682→  const lookup = await lookupSession(input.surreal, input.sessionId);
683→  if (!lookup.ok) {
684→    return { ok: false, error: lookup.error };
685→  }
686→  const { session, record: sessionRecord } = lookup;
687→
688→  // 1. Abort the agent process via adapter if available
689→  if (input.adapter && session.external_session_id) {
690→    try {
691→      await input.adapter.destroySession(session.external_session_id);
692→    } catch (err) {
693→      log.warn("orchestrator.abort", "Failed to destroy sandbox session", {
694→        sessionId: input.sessionId,
695→        externalSessionId: session.external_session_id,
696→        error: String(err),
697→      });
698→    }
699→  }
700→
701→  // 2. Update orchestrator_status to aborted
702→  await input.surreal.update(sessionRecord).merge({
703→    orchestrator_status: "aborted" as OrchestratorStatus,
704→  });
705→
706→  const workspaceRecord = requireWorkspace(session, input.sessionId);
707→
708→  // 3. Remove worktree if branch name exists
709→  if (session.worktree_branch) {
710→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
711→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
712→  }
713→
714→  // 4. Return task to ready
715→  if (session.task_id) {
716→    await input.surreal.update(session.task_id).merge({
717→      status: "ready",
718→      updated_at: new Date(),
719→    });
720→  }
721→
722→  // 5. End the agent session
723→  await input.endAgentSession({
724→    surreal: input.surreal,
725→    workspaceRecord,
726→    sessionId: input.sessionId,
727→    summary: "Session aborted",
728→  });
729→
730→  return {
731→    ok: true,
732→    value: {
733→      aborted: true,
734→      sessionId: input.sessionId,
735→    },
736→  };
737→}
