879→// ---------------------------------------------------------------------------
880→// rejectOrchestratorSession
881→// ---------------------------------------------------------------------------
882→
883→type RejectSessionInput = {
884→  surreal: Surreal;
885→  sessionId: string;
886→  feedback: string;
887→};
888→
889→export async function rejectOrchestratorSession(
890→  input: RejectSessionInput,
891→): Promise<RejectSessionResult> {
892→  const lookup = await lookupSession(input.surreal, input.sessionId);
893→  if (!lookup.ok) {
894→    return { ok: false, error: lookup.error };
895→  }
896→  const { session, record: sessionRecord, status } = lookup;
897→
898→  if (!REJECTABLE_STATUSES.has(status)) {
899→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
900→  }
901→
902→  // 1. Update session status to active (agent resumes work)
903→  await input.surreal.update(sessionRecord).merge({
904→    orchestrator_status: "active" as OrchestratorStatus,
905→    last_feedback: input.feedback,
906→  });
907→
908→  // 2. Return task to in_progress
909→  if (session.task_id) {
910→    await input.surreal.update(session.task_id).merge({
911→      status: "in_progress",
912→      updated_at: new Date(),
913→    });
914→  }
915→
916→  return {
917→    ok: true,
918→    value: {
919→      rejected: true,
920→      continuing: true,
921→    },
922→  };
923→}
924→
925→// ---------------------------------------------------------------------------
926→// sendSessionPrompt
927→// ---------------------------------------------------------------------------
928→
929→type SendPromptInput = {
930→  surreal: Surreal;
931→  sessionId: string;
932→  text: string;
933→  adapter?: SandboxAgentAdapter;
934→};
935→
936→export async function sendSessionPrompt(
937→  input: SendPromptInput,
938→): Promise<PromptSessionResult> {
939→  const lookup = await lookupSession(input.surreal, input.sessionId);
940→  if (!lookup.ok) {
941→    return { ok: false, error: lookup.error };
942→  }
943→  const { session, status } = lookup;
944→
945→  if (!PROMPTABLE_STATUSES.has(status)) {
946→    // Terminal sessions return 404 (session is "gone"), non-terminal return 409 (conflict)
947→    if (TERMINAL_STATUSES.has(status)) {
948→      return { ok: false, error: sessionNotFound(input.sessionId) };
949→    }
950→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "prompt") };
951→  }
952→
953→  // ── Adapter path: delegate to SandboxAgentAdapter ──
954→  if (input.adapter && session.external_session_id) {
955→    try {
956→      const handle = await input.adapter.resumeSession(session.external_session_id);
957→      await handle.prompt([{ type: "text", text: input.text }]);
958→      return { ok: true, value: { delivered: true } };
959→    } catch (err) {
960→      return {
961→        ok: false,
962→        error: {
963→          code: "SESSION_ERROR",
964→          message: `Failed to deliver prompt: ${err instanceof Error ? err.message : String(err)}`,
965→          httpStatus: 500,
966→        },
967→      };
968→    }
969→  }
970→
971→  // ── Legacy path: Agent SDK does not support follow-up prompts ──
972→  return {
973→    ok: false,
974→    error: {
975→      code: "SESSION_ERROR",
976→      message: `Follow-up prompts are not supported with the Agent SDK. Session ${input.sessionId} runs a single query() conversation.`,
977→      httpStatus: 409,
978→    },
979→  };
980→}
