 56→export function createBrainServer(deps: ServerDependencies): ReturnType<typeof Bun.serve> {
 57→  const config = deps.config;
 58→
 59→  // Shell execution — shared by workspace and orchestrator routes
 60→  const shellExec: ShellExec = async (command, args, cwd) => {
 61→    const proc = Bun.spawn([command, ...args], { cwd, stdout: "pipe", stderr: "pipe" });
 62→    const [stdout, stderr] = await Promise.all([
 63→      new Response(proc.stdout).text(),
 64→      new Response(proc.stderr).text(),
 65→    ]);
 66→    const exitCode = await proc.exited;
 67→    return { exitCode, stdout, stderr };
 68→  };
 69→
 70→  const workspaceHandlers = createWorkspaceRouteHandlers(deps, shellExec);
 71→  const chatHandlers = createChatIngressHandlers(deps);
 72→  const entitySearchHandler = createEntitySearchHandler(deps);
 73→  const graphHandler = createGraphRouteHandler(deps);
 74→  const entityDetailHandler = createEntityDetailHandler(deps);
 75→  const entityActionsHandler = createEntityActionsHandler(deps);
 76→  const workItemAcceptHandler = createWorkItemAcceptHandler(deps);
 77→  const branchConversationHandler = createBranchConversationHandler(deps);
 78→  const githubWebhookHandler = createGitHubWebhookHandler(deps);
 79→  const feedHandler = createFeedRouteHandler(deps);
 80→  const chatRouteHandler = createChatRouteHandler(deps);
 81→  const mcpHandlers = createMcpRouteHandlers(deps);
 82→  const intentHandlers = createIntentRouteHandlers(deps);
 83→  const intentSubmissionHandler = createIntentSubmissionHandler(deps);
 84→  const tokenEndpointHandler = createTokenEndpointHandler(deps);
 85→  const bridgeExchangeHandler = createBridgeExchangeHandler(deps);
 86→  const observerHandler = createObserverRouteHandler(deps);
 87→  const graphScanHandler = createGraphScanRouteHandler(deps);
 88→
 89→  // Agent Activator: POST endpoint called by SurrealDB DEFINE EVENT webhook
 90→  const activatorDampener = createLoopDampener(
 91→    { threshold: 4, windowMs: 60_000 },
 92→    undefined,
 93→    (_key, event) => {
 94→      log.info("activator.dampened", "Loop dampener activated", {
 95→        workspaceId: event.workspaceId,
 96→        entityId: event.entityId,
 97→        sourceAgent: event.sourceAgent,
 98→      });
 99→    },
100→  );

  1→/**
  2→ * Unit tests for SandboxAgentAdapter interface.
  3→ *
  4→ * Tests use a mock adapter implementation -- no real SDK, no real SandboxAgent Server.
  5→ * Validates the adapter contract: method signatures, return types, error propagation.
  6→ *
  7→ * Traces: US-01 (spawn), US-04 (prompt), US-05 (resume)
  8→ *
  9→ * Driving port: SandboxAgentAdapter type (injected mock)
 10→ */
 11→import { describe, expect, it } from "bun:test";
 12→import { createMockAdapter } from "../../../app/src/server/orchestrator/sandbox-adapter";
 13→
 14→// ── Tests ──
 15→
 16→describe("SandboxAgentAdapter (mock)", () => {
 17→  // ─── UA-1: createSession returns a SessionHandle with valid ID ───
 18→  // US-01
 19→  it("createSession returns a session handle with a valid ID", async () => {
 20→    // Given a mock sandbox adapter
 21→    const adapter = createMockAdapter();
 22→
 23→    // When a session is created with agent and working directory
 24→    const handle = await adapter.createSession({
 25→      agent: "claude",
 26→      cwd: "/workspace/rate-limiter",
 27→    });
 28→
 29→    // Then the handle has a non-empty ID
 30→    expect(handle.id).toBeTruthy();
 31→    expect(typeof handle.id).toBe("string");
 32→    // And the handle exposes prompt, onEvent, and respondPermission methods
 33→    expect(typeof handle.prompt).toBe("function");
 34→    expect(typeof handle.onEvent).toBe("function");
 35→    expect(typeof handle.respondPermission).toBe("function");
 36→  });
 37→
 38→  // ─── UA-2: prompt delivers messages and returns result ───
 39→  // US-04
 40→  it("prompt delivers messages to an active session", async () => {
 41→    // Given an active session
 42→    const adapter = createMockAdapter();
 43→    const handle = await adapter.createSession({
 44→      agent: "claude",
 45→      cwd: "/workspace/feature",
 46→    });
 47→
 48→    // When a prompt is sent
 49→    const result = await handle.prompt([
 50→      { type: "text", text: "Implement rate limiting with a sliding window" },
 51→    ]);
 52→
 53→    // Then the prompt returns a valid stop reason
 54→    expect(result.stopReason).toBe("end_turn");
 55→  });
 56→
 57→  // ─── UA-3: destroySession completes without error ───
 58→  // US-01
 59→  it("destroySession completes without error for an existing session", async () => {
 60→    // Given an active session
 61→    const adapter = createMockAdapter();
 62→    const handle = await adapter.createSession({
 63→      agent: "claude",
 64→      cwd: "/workspace/cleanup",
 65→    });
 66→
 67→    // When the session is destroyed
 68→    // Then no error is thrown
 69→    await expect(adapter.destroySession(handle.id)).resolves.toBeUndefined();
 70→  });
 71→
 72→  // ─── UA-4: resumeSession returns a SessionHandle for existing session ───
 73→  // US-05
 74→  it("resumeSession returns a handle for a previously created session", async () => {
 75→    // Given a session that was previously created
 76→    const adapter = createMockAdapter();
 77→    const original = await adapter.createSession({
 78→      agent: "claude",
 79→      cwd: "/workspace/restore-test",
 80→    });
 81→
 82→    // When the session is resumed by ID
 83→    const resumed = await adapter.resumeSession(original.id);
 84→
 85→    // Then a valid session handle is returned
 86→    expect(resumed.id).toBe(original.id);
 87→    expect(typeof resumed.prompt).toBe("function");
 88→  });
 89→
 90→  // ─── UA-5: createSession propagates connection errors ───
 91→  // US-01 (error path)
 92→  it("createSession propagates adapter connection errors", async () => {
 93→    // Given an adapter that fails to connect to the SandboxAgent server
 94→    const adapter = createMockAdapter({
 95→      createSession: async () => {
 96→        throw new Error("SandboxAgent server unavailable at localhost:4100");
 97→      },
 98→    });
 99→
100→    // When a session creation is attempted
101→    // Then the error propagates with a meaningful message
102→    await expect(
103→      adapter.createSession({ agent: "claude", cwd: "/workspace/fail" }),
104→    ).rejects.toThrow("SandboxAgent server unavailable");
105→  });
106→
107→  // ─── UA-6: prompt on destroyed session throws ───
108→  // US-04 (error path)
109→  it("prompt on a destroyed session throws an error", async () => {
110→    // Given a session that has been destroyed
111→    const adapter = createMockAdapter();
112→    const handle = await adapter.createSession({
113→      agent: "claude",
114→      cwd: "/workspace/destroyed",
115→    });
116→    await adapter.destroySession(handle.id);
117→
118→    // When a prompt is sent to the destroyed session
119→    // Then an error is thrown indicating the session is gone
120→    await expect(
121→      handle.prompt([{ type: "text", text: "This should fail" }]),
122→    ).rejects.toThrow();
123→  });
124→});
