 24→let eventCounter = 0;
 25→
 26→function makeSessionEvent(
 27→  sessionId: string,
 28→  payload: Record<string, unknown>,
 29→): SessionEvent {
 30→  eventCounter++;
 31→  return {
 32→    id: `evt-${eventCounter}`,
 33→    eventIndex: eventCounter,
 34→    sessionId,
 35→    createdAt: Date.now(),
 36→    connectionId: "conn-test",
 37→    sender: "agent" as const,
 38→    payload: payload as any,
 39→  };
 40→}
 41→
 42→function toolCallEvent(sessionId: string, toolName: string): SessionEvent {
 43→  return makeSessionEvent(sessionId, {
 44→    jsonrpc: "2.0",
 45→    method: "session/update",
 46→    params: {
 47→      sessionId,
 48→      update: {
 49→        sessionUpdate: "tool_call",
 50→        name: toolName,
 51→        toolCallId: `tc-${crypto.randomUUID().slice(0, 8)}`,
 52→      },
 53→    },
 54→  });
 55→}
 56→
 57→function textChunkEvent(sessionId: string, text: string): SessionEvent {
 58→  return makeSessionEvent(sessionId, {
 59→    jsonrpc: "2.0",
 60→    method: "session/update",
 61→    params: {
 62→      sessionId,
 63→      update: {
 64→        sessionUpdate: "agent_message_chunk",
 65→        content: { type: "text", text },
 66→      },
 67→    },
 68→  });
 69→}
 70→
 71→function resultEvent(sessionId: string): SessionEvent {
 72→  return makeSessionEvent(sessionId, {
 73→    jsonrpc: "2.0",
 74→    result: { stopReason: "end_turn" },
 75→  });
 76→}
