 95→function stubBridgeDeps(): SandboxEventBridgeDeps & {
 96→  emitted: Array<{ streamId: string; event: StreamEvent }>;
 97→  updatedSessions: string[];
 98→  stallNotifications: string[];
 99→} {
100→  const emitted: Array<{ streamId: string; event: StreamEvent }> = [];
101→  const updatedSessions: string[] = [];
102→  const stallNotifications: string[] = [];
103→  return {
104→    emitEvent: (streamId, event) => {
105→      emitted.push({ streamId, event });
106→    },
107→    updateLastEventAt: async (sessionId) => {
108→      updatedSessions.push(sessionId);
109→    },
110→    notifyStallDetector: (sessionId) => {
111→      stallNotifications.push(sessionId);
112→    },
113→    emitted,
114→    updatedSessions,
115→    stallNotifications,
116→  };
117→}
