 87→async function assignTaskToSandboxAgent(
 88→  baseUrl: string,
 89→  user: { headers: Record<string, string> },
 90→  workspaceId: string,
 91→  taskId: string,
 92→): Promise<{ agentSessionId: string; streamUrl: string }> {
 93→  const response = await fetch(
 94→    `${baseUrl}/api/orchestrator/${workspaceId}/assign`,
 95→    {
 96→      method: "POST",
 97→      headers: { "Content-Type": "application/json", ...user.headers },
 98→      body: JSON.stringify({ taskId }),
 99→    },
100→  );
101→  if (!response.ok) {
102→    const body = await response.text();
103→    throw new Error(`Failed to assign task: ${response.status} ${body}`);
104→  }
105→  return (await response.json()) as { agentSessionId: string; streamUrl: string };
106→}
