125→async function getSessionStatus(
126→  baseUrl: string,
127→  user: { headers: Record<string, string> },
128→  workspaceId: string,
129→  sessionId: string,
130→): Promise<{ orchestratorStatus: string; sessionType?: string }> {
131→  const response = await fetch(
132→    `${baseUrl}/api/orchestrator/${workspaceId}/sessions/${sessionId}`,
133→    { headers: user.headers },
134→  );
135→  if (!response.ok) {
136→    throw new Error(`Failed to get session status: ${response.status}`);
137→  }
138→  return (await response.json()) as { orchestratorStatus: string; sessionType?: string };
139→}
