/**
 * Queries all observations in a workspace, optionally filtered by source agent.
 */
export async function queryWorkspaceObservations(
  surreal: Surreal,
  workspaceId: string,
  sourceAgent?: string,
): Promise<Array<{
  id: RecordId;
  text: string;
  severity: string;
  status: string;
  source_agent: string;
  observation_type?: string;
  workspace: RecordId<"workspace">;
  created_at: string;
  updated_at?: string;
}>> {
  const workspaceRecord = new RecordId("workspace", workspaceId);

  type ObsRow = {
    id: RecordId;
    text: string;
    severity: string;
    status: string;
    source_agent: string;
    observation_type?: string;
    workspace: RecordId<"workspace">;
    created_at: string;
    updated_at?: string;
